  // Multi-entity phone lookup — returns ALL matches across customers, hospitals, clinics, collaborators
  app.get("/api/phone/lookup-all", requireAuth, async (req: Request, res: Response) => {
    try {
      const phone = req.query.phone as string;
      if (!phone) return res.status(400).json({ error: "Phone parameter required" });

      const normalized = phone.replace(/[\s\-\(\)]/g, "");
      const shortNum = normalized.replace(/^(\+|00)/, "").replace(/^421|^420|^36|^40|^39|^49|^1/, "");

      const matches = (p: string | null | undefined): boolean => {
        if (!p) return false;
        const norm = p.replace(/[\s\-\(\)]/g, "");
        return norm === normalized || norm.endsWith(shortNum) || normalized.endsWith(norm.replace(/^(\+|00)/, "").replace(/^421|^420|^36|^40|^39|^49|^1/, ""));
      };

      const results: Array<{ entityType: string; id: string; name: string; phone: string; subtype?: string }> = [];

      const [allCustomers, allHospitals, allClinics, allCollaborators] = await Promise.all([
        storage.getAllCustomers(),
        storage.getAllHospitals(),
        storage.getAllClinics(),
        storage.getAllCollaborators(),
      ]);

      for (const c of allCustomers) {
        const hit = [c.phone, c.mobile, (c as any).mobile2, (c as any).otherContact].find(p => matches(p));
        if (hit) results.push({ entityType: "customer", id: c.id, name: `${c.firstName} ${c.lastName}`, phone: hit });
      }
      for (const h of allHospitals) {
        if (matches(h.phone)) results.push({ entityType: "hospital", id: h.id, name: h.name, phone: h.phone! });
      }
      for (const c of allClinics) {
        const hit = [(c as any).phone, (c as any).phone2, (c as any).phone3].find((p: string | null) => matches(p));
        if (hit) results.push({ entityType: "clinic", id: c.id, name: c.name, phone: hit, subtype: (c as any).doctorName || undefined });
      }
      for (const c of allCollaborators) {
        const hit = [(c as any).phone, (c as any).mobile, (c as any).mobile2, (c as any).otherContact].find((p: string | null) => matches(p));
        if (hit) results.push({ entityType: "collaborator", id: c.id, name: `${c.firstName} ${c.lastName}`, phone: hit, subtype: (c as any).collaboratorType || undefined });
      }

      res.json(results);
    } catch (error) {
      console.error("Error in phone lookup-all:", error);
      res.status(500).json({ error: "Failed to lookup phone" });
    }
  });

  app.get("/api/customers/lookup-phone", requireAuth, async (req, res) => {
    try {
      const phone = req.query.phone as string;
      if (!phone) return res.status(400).json({ error: "Phone parameter required" });

      const normalized = phone.replace(/[\s\-\(\)]/g, "");
      const shortNum = normalized.replace(/^(\+|00)/, "").replace(/^421|^420|^36|^40|^39|^49|^1/, "");

      const allCustomers = await storage.getAllCustomers();
      const match = allCustomers.find((c: any) => {
        const phones = [c.phone, c.mobile, c.mobile2, c.otherContact].filter(Boolean);
        return phones.some((p: string) => {
          const norm = p.replace(/[\s\-\(\)]/g, "");
          return norm === normalized || norm.endsWith(shortNum) || normalized.endsWith(norm.replace(/^(\+|00)/, "").replace(/^421|^420|^36|^40|^39|^49|^1/, ""));
        });
      });

      if (match) {
        res.json({
          id: match.id,
          name: `${match.firstName} ${match.lastName}`,
          email: match.email,
          phone: match.phone || match.mobile,
          company: (match as any).company || null,
          country: match.country,
        });
      } else {
        res.json(null);
      }
    } catch (error) {
      console.error("Error looking up customer by phone:", error);
      res.status(500).json({ error: "Failed to lookup customer" });
    }
  });

  app.get("/api/customers/:id/audit-report", requireAuth, async (req, res) => {
    try {
      const customer = await storage.getCustomer(req.params.id);
      if (!customer) return res.status(404).json({ error: "Customer not found" });

      const [documents, debtRecords, notes, potentialCase, invoices, consents] = await Promise.all([
        db.select().from(customerDocuments).where(eq(customerDocuments.customerId, req.params.id)).orderBy(customerDocuments.createdAt),
        db.select().from(customerDebtCollection).where(eq(customerDebtCollection.customerId, req.params.id)),
        storage.getCustomerNotes(req.params.id),
        storage.getCustomerPotentialCase(req.params.id),
        storage.getInvoicesByCustomer(req.params.id),
        db.select().from(customerConsents).where(eq(customerConsents.customerId, req.params.id)),
      ]);

      const contracts = documents.filter(d => d.documentType === "contract");
      const docInvoices = documents.filter(d => d.documentType === "invoice");

      const customerCollections = await db.select().from(collections).where(eq(collections.customerId, req.params.id));
      const labResults = [];
      for (const col of customerCollections) {
        const results = await storage.getCollectionLabResultsByCollection(col.id);
        labResults.push({ collection: col, results });
      }

      let activityLogs: any[] = [];
      try {
        activityLogs = await db.select().from(activityLogsTable)
          .where(eq(activityLogsTable.entityId, req.params.id))
          .orderBy(activityLogsTable.createdAt)
          .limit(200);
      } catch {}

      let contactHistory: any[] = [];
      try {
        contactHistory = await db.select().from(campaignContactHistory)
          .where(eq(campaignContactHistory.customerId, req.params.id))
          .orderBy(campaignContactHistory.contactedAt)
          .limit(100);
      } catch {}

      let emailNotifications: any[] = [];
      try {
        emailNotifications = await db.select().from(customerEmailNotifications)
          .where(eq(customerEmailNotifications.customerId, req.params.id))
          .orderBy(customerEmailNotifications.receivedAt)
          .limit(100);
      } catch {}

      res.json({
        customer,
        contracts,
        documentInvoices: docInvoices,
        invoices,
        debtRecords,
        notes,
        potentialCase,
        collections: customerCollections,
        labResults,
        activityLogs,
        contactHistory,
        consents,
        emailNotifications,
      });
    } catch (error) {
      console.error("Error fetching customer audit report:", error);
      res.status(500).json({ error: "Failed to fetch audit report" });
    }
  });

