  // Create invoice from scheduled invoice
  app.post("/api/scheduled-invoices/:id/create", requireAuth, async (req, res) => {
    try {
      const scheduled = await storage.getScheduledInvoiceById(req.params.id);
      if (!scheduled) {
        return res.status(404).json({ error: "Scheduled invoice not found" });
      }
      if (scheduled.status !== "pending") {
        return res.status(400).json({ error: "Scheduled invoice is not pending" });
      }

      const { billingDetailsId, billingChoice, templateId } = req.body || {};

      // If billingChoice is "indexus" and billingDetailsId provided, load billing details
      let billingOverride: any = null;
      if (billingChoice === "indexus" && billingDetailsId) {
        const [bd] = await db.select().from(billingDetails).where(eq(billingDetails.id, billingDetailsId));
        if (bd) {
          billingOverride = {
            billingDetailsId: bd.id,
            billingCompanyName: bd.companyName || bd.fullName,
            billingAddress: bd.address,
            billingCity: bd.city,
            billingZip: bd.postalCode,
            billingCountry: bd.countryCode,
            billingTaxId: bd.ico || bd.dic,
            billingVatId: bd.vatNumber || bd.taxId,
            billingEmail: bd.email,
            billingPhone: bd.phone,
            billingBankName: bd.bankName,
            billingBankIban: bd.bankIban,
            billingBankSwift: bd.bankSwift,
          };
        }
      }

      // Generate invoice number from number range or fallback
      let invoiceNumber = "";
      if (scheduled.numberRangeId) {
        const [range] = await db.select().from(numberRanges).where(eq(numberRanges.id, scheduled.numberRangeId));
        if (range) {
          const nextNum = (range.lastNumberUsed || 0) + 1;
          invoiceNumber = `${range.prefix || ""}${String(nextNum).padStart(range.digitsToGenerate || 6, "0")}${range.suffix || ""}`;
          await db.update(numberRanges).set({ lastNumberUsed: nextNum }).where(eq(numberRanges.id, range.id));
        }
      }
      if (!invoiceNumber) {
        const date = new Date();
        const year = date.getFullYear();
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const random = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
        invoiceNumber = `INV-${year}${month}-${random}`;
      }

      // Check for duplicate invoice number
      const existing = await db.select({ id: invoices.id }).from(invoices).where(eq(invoices.invoiceNumber, invoiceNumber)).limit(1);
      if (existing.length > 0) {
        const suffix = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
        invoiceNumber = `${invoiceNumber}-${suffix}`;
      }

      const now = new Date();
      const dueDate = new Date(now.getTime() + (scheduled.paymentTermDays || 14) * 24 * 60 * 60 * 1000);

      // Create the actual invoice from the scheduled data with all metadata
      const invoice = await storage.createInvoice({
        invoiceNumber,
        customerId: scheduled.customerId,
        billingDetailsId: billingOverride?.billingDetailsId || scheduled.billingDetailsId,
        currency: scheduled.currency,
        totalAmount: scheduled.totalAmount,
        vatAmount: scheduled.vatAmount || "0",
        subtotal: scheduled.subtotal || scheduled.totalAmount,
        vatRate: scheduled.vatRate || "0",
        status: "generated",
        paymentTermDays: scheduled.paymentTermDays,
        variableSymbol: invoiceNumber,
        constantSymbol: scheduled.constantSymbol,
        specificSymbol: scheduled.specificSymbol || invoiceNumber,
        barcodeType: scheduled.barcodeType,
        barcodeValue: invoiceNumber,
        issueDate: now,
        dueDate: dueDate,
        deliveryDate: now,
        customerName: scheduled.customerName,
        customerAddress: scheduled.customerAddress,
        customerCity: scheduled.customerCity,
        customerZip: scheduled.customerZip,
        customerCountry: scheduled.customerCountry,
        customerEmail: scheduled.customerEmail,
        customerPhone: scheduled.customerPhone,
        customerCompanyName: scheduled.customerCompanyName,
        customerTaxId: scheduled.customerTaxId,
        customerVatId: scheduled.customerVatId,
        billingCompanyName: billingOverride?.billingCompanyName || scheduled.billingCompanyName,
        billingAddress: billingOverride?.billingAddress || scheduled.billingAddress,
        billingCity: billingOverride?.billingCity || scheduled.billingCity,
        billingZip: billingOverride?.billingZip || scheduled.billingZip,
        billingCountry: billingOverride?.billingCountry || scheduled.billingCountry,
        billingTaxId: billingOverride?.billingTaxId || scheduled.billingTaxId,
        billingVatId: billingOverride?.billingVatId || scheduled.billingVatId,
        billingEmail: billingOverride?.billingEmail || scheduled.billingEmail,
        billingPhone: billingOverride?.billingPhone || scheduled.billingPhone,
        billingBankName: billingOverride?.billingBankName || scheduled.billingBankName,
        billingBankIban: billingOverride?.billingBankIban || scheduled.billingBankIban,
        billingBankSwift: billingOverride?.billingBankSwift || scheduled.billingBankSwift,
        billingBankAccountNumber: billingOverride?.billingBankAccountNumber || scheduled.billingBankAccountNumber,
        qrCodeType: scheduled.qrCodeType,
        qrCodeData: scheduled.qrCodeData,
        epcQrCodeData: scheduled.epcQrCodeData,
        qrCodeEnabled: scheduled.qrCodeEnabled,
        itemsSnapshot: scheduled.items,
        wizardCreatedAt: scheduled.wizardCreatedAt,
      } as any);

      // Create invoice items from the scheduled items
      const items = scheduled.items as any[];
      if (items && items.length > 0) {
        await storage.createInvoiceItems(
          items.map((item: any) => {
            const qty = parseFloat(item.quantity || "1");
            const price = parseFloat(item.unitPrice || "0");
            const lineTotal = item.totalPrice || String(qty * price);
            return {
              invoiceId: invoice.id,
              name: item.name || item.description || "Item",
              productId: item.productId,
              description: item.description,
              quantity: String(item.quantity || "1"),
              unitPrice: String(item.unitPrice || "0"),
              totalPrice: lineTotal,
              lineTotal: lineTotal,
              vatRate: String(item.vatRate || "0"),
            };
          })
        );
      }

      // Update scheduled invoice status
      await storage.updateScheduledInvoice(scheduled.id, {
        status: "created",
        createdInvoiceId: invoice.id,
      } as any);

      console.log(`[ScheduledInvoice] Created invoice ${invoice.id} (${invoiceNumber}) from scheduled ${scheduled.id}`);
      res.status(201).json(invoice);

      generateAndSaveInvoicePdf(invoice.id).catch(err =>
        console.error("[ScheduledInvoice] Background PDF generation failed:", err)
      );
    } catch (error: any) {
      console.error("Error creating invoice from scheduled:", error?.message, error?.stack);
      res.status(500).json({ error: "Failed to create invoice", details: error?.message });
    }
  });

