  app.get("/api/customers/:customerId/activity-logs", requireAuth, async (req, res) => {
    try {
      const logs = await storage.getActivityLogsByEntity("customer", req.params.customerId);
      
      // Also get consent logs (stored with entityType="consent" but with customerId in details)
      const consentLogs = await storage.getConsentLogsByCustomerId(req.params.customerId);
      
      // Also get campaign participations from campaign_contacts table
      const campaignContacts = await storage.getCampaignContactsByCustomer(req.params.customerId);
      
      // Create synthetic activity logs for campaign participations that don't have real logs
      const campaignLogs = campaignContacts.map(cc => ({
        id: `campaign-${cc.id}`,
        userId: null,
        action: "campaign_joined",
        entityType: "customer",
        entityId: req.params.customerId,
        entityName: null,
        details: JSON.stringify({ 
          campaignId: cc.campaignId, 
          campaignName: cc.campaign?.name || "Kampaň",
          synthetic: true 
        }),
        ipAddress: null,
        createdAt: cc.createdAt,
      }));
      
      // Filter out synthetic logs for campaigns that already have real activity logs
      const existingCampaignIds = new Set(
        logs
          .filter(l => l.action === "campaign_joined")
          .map(l => {
            try {
              const details = JSON.parse(l.details || "{}");
              return details.campaignId;
            } catch { return null; }
          })
          .filter(Boolean)
      );
      
      const newCampaignLogs = campaignLogs.filter(cl => {
        try {
          const details = JSON.parse(cl.details || "{}");
          return !existingCampaignIds.has(details.campaignId);
        } catch { return true; }
      });
      
      // Combine and sort by date
      const allLogs = [...logs, ...consentLogs, ...newCampaignLogs].sort((a, b) => 
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
      
      res.json(allLogs);
    } catch (error) {
      console.error("Error fetching customer activity logs:", error);
      res.status(500).json({ error: "Failed to fetch customer activity logs" });
    }
  });

  app.get("/api/collaborator-call-logs", requireAuth, async (req, res) => {
    try {
      const countryCodes = (req.query.countries as string || "").split(",").filter(Boolean);
      const singleCollaboratorId = req.query.collaboratorId as string | undefined;
      const conditions: any[] = [];
      if (singleCollaboratorId) {
        conditions.push(eq(callLogs.userId, singleCollaboratorId));
      } else if (countryCodes.length > 0) {
        const collabIds = await db.select({ id: collaborators.id })
          .from(collaborators)
          .where(inArray(collaborators.countryCode, countryCodes));
        const ids = collabIds.map(c => c.id);
        if (ids.length === 0) return res.json([]);
        conditions.push(inArray(callLogs.userId, ids));
      } else {
        const collabIds = await db.select({ id: collaborators.id }).from(collaborators);
        const ids = collabIds.map(c => c.id);
        if (ids.length === 0) return res.json([]);
        conditions.push(inArray(callLogs.userId, ids));
      }
      const logs = await db.select({
        id: callLogs.id,
        collaboratorId: callLogs.userId,
        phoneNumber: callLogs.phoneNumber,
        direction: callLogs.direction,
        status: callLogs.status,
        startedAt: callLogs.startedAt,
        endedAt: callLogs.endedAt,
        durationSeconds: callLogs.durationSeconds,
        notes: callLogs.notes,
        customerId: callLogs.customerId,
        metadata: callLogs.metadata,
      }).from(callLogs)
        .where(and(...conditions))
        .orderBy(desc(callLogs.startedAt))
        .limit(500);
      res.json(logs);
    } catch (error) {
      console.error("Error fetching collaborator call logs:", error);
      res.status(500).json({ error: "Failed to fetch collaborator call logs" });
    }
  });

  // Shared contact-history builder — works for customers, hospitals, clinics, collaborators, persons
  const buildContactHistory = async (entityId: string, includeAgentLogs = false): Promise<any[]> => {
    const [fetchedCallLogs, messages, campaignHistory, allUsers, inboundLogs] = await Promise.all([
      storage.getCallLogsByCustomer(entityId),
      storage.getCommunicationMessagesByCustomer(entityId),
      storage.getCampaignContactHistoryByCustomer(entityId),
      storage.getAllUsers(),
      db.select({
        log: inboundCallLogs,
        queueName: inboundQueues.name,
      }).from(inboundCallLogs)
        .leftJoin(inboundQueues, eq(inboundCallLogs.queueId, inboundQueues.id))
        .where(eq(inboundCallLogs.customerId, entityId))
        .orderBy(desc(inboundCallLogs.enteredQueueAt)),
    ]);

    // For collaborators/persons: also include calls they made as agents
    const agentCallLogs = includeAgentLogs ? await storage.getCallLogsByUser(entityId) : [];

    // Merge call logs, dedup by id
    const seenCallIds = new Set<number>();
    const callLogsList: typeof fetchedCallLogs = [];
    for (const c of fetchedCallLogs) { if (c.id) { seenCallIds.add(c.id); callLogsList.push(c); } }
    for (const c of agentCallLogs) { if (c.id && !seenCallIds.has(c.id)) callLogsList.push(c); }

    const customerId = entityId;

    
      const userMap = new Map(allUsers.map(u => [u.id, `${u.firstName || ""} ${u.lastName || ""}`.trim() || u.username]));
      
      const statusLabels: Record<string, string> = {
        pending: "Čakajúci", contacted: "Kontaktovaný", completed: "Dokončený",
        failed: "Neúspešný", no_answer: "Nedvíha", callback_scheduled: "Spätné volanie",
        not_interested: "Nemá záujem",
      };
      
      const callStatusLabels: Record<string, string> = {
        initiated: "Začatý", ringing: "Zvonenie", answered: "Zodvihnutý",
        completed: "Dokončený", failed: "Neúspešný", no_answer: "Nedvíha",
        busy: "Obsadený", cancelled: "Zrušený",
      };

      const historyItems: any[] = [];

      for (const call of callLogsList) {
        const agentName = userMap.get(call.userId) || "Neznámy";
        const duration = call.durationSeconds ? `${Math.floor(call.durationSeconds / 60)}:${String(call.durationSeconds % 60).padStart(2, "0")}` : null;
        historyItems.push({
          id: `call-${call.id}`,
          type: "call",
          direction: call.direction || "outbound",
          timestamp: call.startedAt || call.createdAt,
          status: callStatusLabels[call.status] || call.status,
          statusCode: call.status,
          agentName,
          agentId: call.userId,
          content: `Hovor ${call.direction === "inbound" ? "prichádzajúci" : "odchádzajúci"}: ${call.phoneNumber}`,
          details: duration ? `Trvanie: ${duration}` : null,
          duration: call.durationSeconds,
          notes: call.notes,
          campaignId: call.campaignId,
          callLogId: call.id,
          campaignContactId: call.campaignContactId || null,
        });
      }

      const existingCallLogIds = new Set(callLogsList.filter(c => c.id).map(c => c.id));
      for (const { log: inLog, queueName } of inboundLogs) {
        if (inLog.callLogId && existingCallLogIds.has(inLog.callLogId)) continue;
        const agentName = inLog.assignedAgentId ? (userMap.get(inLog.assignedAgentId) || "Neznámy") : null;
        const inboundStatusLabels: Record<string, string> = {
          queued: "Vo fronte", ringing: "Zvonenie", answered: "Zodvihnutý",
          completed: "Dokončený", abandoned: "Zrušený volajúcim", timeout: "Časový limit",
          overflow: "Pretečenie", transferred: "Presmerovaný",
        };
        const waitDur = inLog.waitDurationSeconds || 0;
        const talkDur = inLog.talkDurationSeconds || 0;
        const durationStr = talkDur > 0 ? `${Math.floor(talkDur / 60)}:${String(talkDur % 60).padStart(2, "0")}` : null;
        const waitStr = waitDur > 0 ? `Čakanie: ${waitDur}s` : null;
        const detailParts = [durationStr ? `Trvanie: ${durationStr}` : null, waitStr].filter(Boolean);
        historyItems.push({
          id: `inbound-${inLog.id}`,
          type: "call",
          direction: "inbound",
          timestamp: inLog.enteredQueueAt || inLog.createdAt,
          status: inboundStatusLabels[inLog.status] || inLog.status,
          statusCode: inLog.status,
          agentName,
          agentId: inLog.assignedAgentId,
          content: `Prichádzajúci hovor: ${inLog.callerNumber}${queueName ? ` → ${queueName}` : ""}`,
          details: detailParts.length > 0 ? detailParts.join(", ") : null,
          duration: talkDur || null,
          notes: inLog.abandonReason === "caller_hangup" ? "Zákazník ukončil hovor" : null,
          queueName: queueName || null,
          inboundCallLogId: inLog.id,
        });
      }

      for (const msg of messages) {
        const msgType = (msg as any).type === "sms" ? "sms" : "email";
        historyItems.push({
          id: `msg-${msg.id}`,
          type: msgType,
          direction: (msg as any).direction || "outbound",
          timestamp: (msg as any).createdAt || (msg as any).sentAt,
          status: ({ sent: "Odoslaný", delivered: "Doručený", read: "Prečítaný", failed: "Neúspešný", draft: "Koncept", received: "Prijatý" } as Record<string, string>)[(msg as any).status || "sent"] || (msg as any).status || "Odoslaný",
          statusCode: (msg as any).status,
          agentName: (msg as any).userId ? (userMap.get((msg as any).userId) || null) : null,
          agentId: (msg as any).userId || null,
          content: msgType === "email" 
            ? ((msg as any).subject || "Email") 
            : ((msg as any).content?.substring(0, 100) || "SMS"),
          details: msgType === "email" ? (msg as any).content : null,
          htmlBody: msgType === "email" ? (msg as any).content : null,
          fullContent: msgType === "sms" ? (msg as any).content : null,
          recipientEmail: (msg as any).recipientEmail || null,
          recipientPhone: (msg as any).recipientPhone || null,
          sentiment: (msg as any).aiSentiment || null,
        });
      }

      const histCampaignIds = [...new Set(campaignHistory.map(h => h.campaignId).filter(Boolean))] as string[];
      const callCampaignIdsForDisp = [...new Set(callLogsList.map(c => c.campaignId).filter(Boolean))] as string[];
      const allCampaignIdsForDisp = [...new Set([...histCampaignIds, ...callCampaignIdsForDisp])];
      const allDispositions = allCampaignIdsForDisp.length > 0
        ? await db.select().from(campaignDispositions).where(inArray(campaignDispositions.campaignId, allCampaignIdsForDisp))
        : [];
      const dispCodeToName = new Map<string, { name: string; color: string | null; icon: string | null; actionType: string }>();
      const dispCampaignCodeToInfo = new Map<string, { name: string; color: string | null; icon: string | null }>();
      for (const d of allDispositions) {
        dispCodeToName.set(d.code, { name: d.name, color: d.color, icon: d.icon, actionType: d.actionType });
        dispCampaignCodeToInfo.set(`${d.campaignId}::${d.code}`, { name: d.name, color: d.color, icon: d.icon });
      }

      // Attach current disposition info to call history items
      // Look up by entity ID across ALL entity type columns (customer/hospital/clinic/collaborator)
      const entityCampaignContacts = await db.select({
        id: campaignContacts.id,
        campaignId: campaignContacts.campaignId,
        dispositionCode: campaignContacts.dispositionCode,
        dispositionChecklistCodes: campaignContacts.dispositionChecklistCodes,
      }).from(campaignContacts).where(
        or(
          eq(campaignContacts.customerId, customerId),
          eq(campaignContacts.hospitalId, customerId),
          eq(campaignContacts.clinicId, customerId),
          eq(campaignContacts.collaboratorId, customerId),
        )
      );

      // Map by cc.id for direct campaignContactId matching
      const ccDispMapById = new Map<string, { campaignId: string; dispositionCode: string | null; checklistCodes: string[] | null }>();
      // Map by campaignId for fallback matching when campaignContactId is not on the call log
      const ccDispByCampaignId = new Map<string, { dispositionCode: string | null; checklistCodes: string[] | null }>();
      for (const cc of entityCampaignContacts) {
        ccDispMapById.set(cc.id, { campaignId: cc.campaignId, dispositionCode: cc.dispositionCode, checklistCodes: cc.dispositionChecklistCodes });
        // Prefer the entry that has a disposition set
        const existing = ccDispByCampaignId.get(cc.campaignId);
        if (!existing || (cc.dispositionCode && !existing.dispositionCode)) {
          ccDispByCampaignId.set(cc.campaignId, { dispositionCode: cc.dispositionCode, checklistCodes: cc.dispositionChecklistCodes });
        }
      }

      for (const item of historyItems) {
        if (item.type === "call") {
          let disp: { dispositionCode: string | null; checklistCodes: string[] | null; campaignId: string } | null = null;
          if (item.campaignContactId && ccDispMapById.has(item.campaignContactId)) {
            const d = ccDispMapById.get(item.campaignContactId)!;
            disp = { ...d, campaignId: d.campaignId };
          } else if (item.campaignId && ccDispByCampaignId.has(item.campaignId)) {
            const d = ccDispByCampaignId.get(item.campaignId)!;
            disp = { ...d, campaignId: item.campaignId };
          }
          if (disp?.dispositionCode) {
            const key = `${disp.campaignId}::${disp.dispositionCode}`;
            const dInfo = dispCampaignCodeToInfo.get(key) || dispCodeToName.get(disp.dispositionCode);
            item.dispositionCode = disp.dispositionCode;
            item.dispositionName = dInfo?.name || null;
            item.dispositionColor = dInfo?.color || null;
            item.dispositionChecklistCodes = disp.checklistCodes || [];
            item.dispositionChecklistNames = (disp.checklistCodes || []).map((code: string) => {
              const ck = dispCampaignCodeToInfo.get(`${disp!.campaignId}::${code}`) || dispCodeToName.get(code);
              return ck?.name || code;
            });
          }
        }
      }

      for (const h of campaignHistory) {
        const agentName = userMap.get(h.userId) || "Neznámy";
        const actionLabels: Record<string, string> = {
          status_change: "Zmena statusu",
          note_added: "Poznámka pridaná",
          callback_set: "Spätné volanie nastavené",
        };
        
        let content = actionLabels[h.action] || h.action;
        if (h.action === "status_change" && h.previousStatus && h.newStatus) {
          content = `${statusLabels[h.previousStatus] || h.previousStatus} → ${statusLabels[h.newStatus] || h.newStatus}`;
        }

        let dispositionName: string | null = null;
        let dispositionColor: string | null = null;
        let dispositionIcon: string | null = null;
        const notesVal = h.notes || null;
        if (notesVal && dispCodeToName.has(notesVal)) {
          const dInfo = dispCodeToName.get(notesVal)!;
          dispositionName = dInfo.name;
          dispositionColor = dInfo.color;
          dispositionIcon = dInfo.icon;
        }
        
        historyItems.push({
          id: `cch-${h.id}`,
          type: "disposition",
          timestamp: h.createdAt,
          agentName,
          agentId: h.userId,
          content,
          details: dispositionName ? null : notesVal,
          dispositionCode: notesVal,
          dispositionName,
          dispositionColor,
          dispositionIcon,
          campaignName: h.campaignName || null,
          campaignId: h.campaignId || null,
          action: h.action,
          previousStatus: h.previousStatus,
          newStatus: h.newStatus,
          metadata: (h.metadata as any) || null,
        });
      }

    historyItems.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    return historyItems;
  };

  // Comprehensive Contact History API — entity-aware routes
