  app.post("/api/campaigns/:id/phases/:phaseId/activate", requireAuth, async (req, res) => {
    try {
      const phase = await storage.getCampaignPhase(req.params.phaseId);
      if (!phase || phase.campaignId !== req.params.id) return res.status(404).json({ error: "Phase not found" });
      if (phase.status !== "draft") return res.status(400).json({ error: "Only draft phases can be activated" });

      const contactPhases = await storage.getCampaignContactPhases(phase.id);
      if (contactPhases.length === 0) {
        const campaignContacts = await storage.getCampaignContacts(req.params.id);
        if (campaignContacts.length === 0) return res.status(400).json({ error: "No contacts in campaign" });
        const cpData = campaignContacts.map(cc => ({
          campaignId: req.params.id,
          contactId: cc.id,
          phaseId: phase.id,
          status: "pending" as const,
        }));
        await storage.createCampaignContactPhases(cpData);
      }

      const updated = await storage.updateCampaignPhase(phase.id, {
        status: "active",
        scheduledStartAt: new Date(),
      });
      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ error: error.message || "Failed to activate phase" });
    }
  });

  app.post("/api/campaigns/:id/phases/:phaseId/evaluate", requireAuth, async (req, res) => {
    try {
      const phase = await storage.getCampaignPhase(req.params.phaseId);
      if (!phase || phase.campaignId !== req.params.id) return res.status(404).json({ error: "Phase not found" });
      if (phase.status !== "active") return res.status(400).json({ error: "Only active phases can be evaluated" });

      const updated = await storage.updateCampaignPhase(phase.id, {
        status: "evaluating",
      });

      const contactPhases = await storage.getCampaignContactPhases(phase.id);
      const campaignContacts = await storage.getCampaignContacts(req.params.id);

      const updatePromises = contactPhases
        .filter(cp => cp.status === "pending" || cp.status === "in_progress")
        .map(cp => {
          const cc = campaignContacts.find(c => c.id === cp.contactId);
          return storage.updateCampaignContactPhase(cp.id, {
            status: "completed",
            result: cc?.dispositionCode || cc?.status || "no_result",
            completedAt: new Date(),
          });
        });
      await Promise.all(updatePromises);

      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ error: error.message || "Failed to evaluate phase" });
    }
  });

  app.post("/api/campaigns/:id/phases/:phaseId/transition", requireAuth, async (req, res) => {
    try {
      const phase = await storage.getCampaignPhase(req.params.phaseId);
      if (!phase || phase.campaignId !== req.params.id) return res.status(404).json({ error: "Phase not found" });

      const { targetPhaseId, includeStatuses, excludeStatuses } = req.body;
      if (!targetPhaseId) return res.status(400).json({ error: "Target phase ID required" });

      const targetPhase = await storage.getCampaignPhase(targetPhaseId);
      if (!targetPhase || targetPhase.campaignId !== req.params.id) return res.status(404).json({ error: "Target phase not found" });

      const contactPhases = await storage.getCampaignContactPhases(phase.id);
      const qualifyingContacts = contactPhases.filter(cp => {
        if (cp.status !== "completed") return false;
        if (includeStatuses && includeStatuses.length > 0) {
          return includeStatuses.includes(cp.result);
        }
        if (excludeStatuses && excludeStatuses.length > 0) {
          return !excludeStatuses.includes(cp.result);
        }
        return true;
      });

      const existingTargetPhases = await storage.getCampaignContactPhases(targetPhaseId);
      const existingContactIds = new Set(existingTargetPhases.map(cp => cp.contactId));
      const deduped = qualifyingContacts.filter(cp => !existingContactIds.has(cp.contactId));

      const newContactPhases = deduped.map(cp => ({
        campaignId: req.params.id,
        contactId: cp.contactId,
        phaseId: targetPhaseId,
        status: "pending" as const,
      }));

      const created = await storage.createCampaignContactPhases(newContactPhases);

      await storage.updateCampaignPhase(phase.id, {
        status: "completed",
        completedAt: new Date(),
        transitionRules: { targetPhaseId, includeStatuses, excludeStatuses },
      });

      const campaign = await storage.getCampaign(req.params.id);
      const transUser = await storage.getUser(req.session.user!.id);
      const transUserName = transUser?.fullName || transUser?.username || "Agent";
      
      for (const cp of created) {
        const campaignContact = await storage.getCampaignContact(cp.contactId);
        if (campaignContact) {
          await logCampaignTimeline(
            campaignContact, campaign, targetPhase.type || "phone", "phase_entered",
            req.session.user!.id, transUserName,
            {
              phaseId: targetPhaseId,
              phaseName: targetPhase.name,
              phaseNumber: targetPhase.phaseNumber,
              metadata: { fromPhaseId: phase.id, fromPhaseName: phase.name },
            }
          );
        }
      }
      
      for (const cp of qualifyingContacts) {
        const campaignContact = await storage.getCampaignContact(cp.contactId);
        if (campaignContact) {
          await logCampaignTimeline(
            campaignContact, campaign, phase.type || "phone", "phase_completed",
            req.session.user!.id, transUserName,
            {
              phaseId: phase.id,
              phaseName: phase.name,
              phaseNumber: phase.phaseNumber,
              status: cp.result || "completed",
            }
          );
        }
      }

      res.json({ transitioned: created.length, total: contactPhases.length });
    } catch (error: any) {
      res.status(500).json({ error: error.message || "Failed to transition contacts" });
    }
  });

  app.get("/api/campaigns/:id/quota-check", requireAuth, async (req, res) => {
    try {
      const campaignId = req.params.id;
      const userId = req.session.user!.id;

      const opSettings = await db.select().from(campaignOperatorSettings)
        .where(and(
          eq(campaignOperatorSettings.campaignId, campaignId),
          eq(campaignOperatorSettings.userId, userId)
        ))
        .limit(1);
      const setting = opSettings[0];
      if (!setting) return res.json({ quotas: null, usage: null, blocked: false });

      const dailyCallQuota = setting.dailyCallQuota ?? null;
      const dailyEmailQuota = setting.dailyEmailQuota ?? null;
      const dailySmsQuota = setting.dailySmsQuota ?? null;

      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const todayISO = today.toISOString();

      const callsToday = await db.select({ count: sql<number>`count(*)` })
        .from(callLogs)
        .where(and(
          eq(callLogs.campaignId, campaignId),
          eq(callLogs.userId, userId),
          eq(callLogs.direction, "outbound"),
          gte(callLogs.createdAt, new Date(todayISO))
        ));

      const emailsToday = await db.select({ count: sql<number>`count(*)` })
        .from(communicationMessages)
        .where(and(
          eq(communicationMessages.userId, userId),
          eq(communicationMessages.type, "email"),
          eq(communicationMessages.direction, "outbound"),
          gte(communicationMessages.createdAt, new Date(todayISO))
        ));

      const smsToday = await db.select({ count: sql<number>`count(*)` })
        .from(communicationMessages)
        .where(and(
          eq(communicationMessages.userId, userId),
          eq(communicationMessages.type, "sms"),
          eq(communicationMessages.direction, "outbound"),
          gte(communicationMessages.createdAt, new Date(todayISO))
        ));

      const usage = {
        calls: Number(callsToday[0]?.count || 0),
        emails: Number(emailsToday[0]?.count || 0),
        sms: Number(smsToday[0]?.count || 0),
      };

      const blocked = {
        calls: dailyCallQuota !== null && usage.calls >= dailyCallQuota,
        emails: dailyEmailQuota !== null && usage.emails >= dailyEmailQuota,
        sms: dailySmsQuota !== null && usage.sms >= dailySmsQuota,
      };

      const result = {
        quotas: { calls: dailyCallQuota, emails: dailyEmailQuota, sms: dailySmsQuota },
        usage,
        blocked,
        anyBlocked: blocked.calls || blocked.emails || blocked.sms,
      };
      console.log(`[Quotas] Campaign=${campaignId} User=${userId} quotas=${JSON.stringify(result.quotas)} usage=${JSON.stringify(usage)} blocked=${JSON.stringify(blocked)}`);
      res.json(result);
    } catch (error: any) {
      res.status(500).json({ error: error.message || "Failed to check quota" });
    }
  });

  app.post("/api/campaigns/:id/phases/:phaseId/auto-transition", requireAuth, async (req, res) => {
    try {
      const phase = await storage.getCampaignPhase(req.params.phaseId);
      if (!phase || phase.campaignId !== req.params.id) return res.status(404).json({ error: "Phase not found" });

      const rules: any = phase.transitionRules || {};
      const mode = (phase as any).transitionMode || "manual";
      if (mode === "manual") return res.status(400).json({ error: "Phase is set to manual transition" });

      const maxAttempts = rules.maxAttempts ?? null;
      const daysSinceLastAttempt = rules.daysSinceLastAttempt ?? null;
      const moveDispositions: string[] = rules.moveDispositions || [];
      const keepDispositions: string[] = rules.keepDispositions || [];
      const targetPhaseId = rules.targetPhaseId || null;

      if (!targetPhaseId) return res.status(400).json({ error: "No target phase configured" });

      const targetPhase = await storage.getCampaignPhase(targetPhaseId);
      if (!targetPhase) return res.status(404).json({ error: "Target phase not found" });

      const contactPhases = await storage.getCampaignContactPhases(phase.id);
      const now = new Date();
      const qualifyingContacts: typeof contactPhases = [];

      for (const cp of contactPhases) {
        if (cp.status === "completed" || cp.status === "skipped") continue;

        const campaignContact = await storage.getCampaignContact(cp.contactId);
        if (!campaignContact) continue;

        let shouldMove = false;

        if (keepDispositions.length > 0 && cp.result && keepDispositions.includes(cp.result)) {
          continue;
        }

        if (moveDispositions.length > 0 && cp.result && moveDispositions.includes(cp.result)) {
          shouldMove = true;
        }

        if (!shouldMove && maxAttempts && campaignContact.attemptCount >= maxAttempts) {
          shouldMove = true;
        }

        if (!shouldMove && daysSinceLastAttempt && campaignContact.lastAttemptAt) {
          const daysDiff = (now.getTime() - new Date(campaignContact.lastAttemptAt).getTime()) / (1000 * 60 * 60 * 24);
          if (daysDiff >= daysSinceLastAttempt) shouldMove = true;
        }

        if (shouldMove) qualifyingContacts.push(cp);
      }

      const existingTargetPhases = await storage.getCampaignContactPhases(targetPhaseId);
      const existingContactIds = new Set(existingTargetPhases.map(cp => cp.contactId));
      const deduped = qualifyingContacts.filter(cp => !existingContactIds.has(cp.contactId));

      const newContactPhases = deduped.map(cp => ({
        campaignId: req.params.id,
        contactId: cp.contactId,
        phaseId: targetPhaseId,
        status: "pending" as const,
      }));

      const created = await storage.createCampaignContactPhases(newContactPhases);

      for (const cp of qualifyingContacts) {
        await storage.updateCampaignContactPhase(cp.id, { status: "completed", completedAt: new Date() });
      }

      await storage.updateCampaignPhase(phase.id, { lastAutoTransitionAt: new Date() } as any);

      res.json({
        evaluated: contactPhases.length,
        qualifying: qualifyingContacts.length,
        transitioned: created.length,
        skippedDuplicates: qualifyingContacts.length - deduped.length,
      });
    } catch (error: any) {
      res.status(500).json({ error: error.message || "Failed to auto-transition" });
    }
  });

