  app.post("/api/mobile/call-log/:id/trigger-server-recording", async (req, res) => {
    try {
      const tokenData = await getMobileCollaboratorFromToken(req);
      if (!tokenData) return res.status(401).json({ error: "Unauthorized" });

      const collaborator = await storage.getCollaborator(tokenData.collaboratorId);
      if (!collaborator || !collaborator.mobileCallRecording) {
        return res.status(403).json({ error: "Call recording not enabled" });
      }

      let ext = await storage.getSipExtensionByCollaboratorId(tokenData.collaboratorId);
      if (!ext && collaborator.mobileSipExtensionId) {
        ext = await storage.getSipExtensionById(collaborator.mobileSipExtensionId);
        if (ext) {
          storage.assignSipExtensionToCollaborator(ext.id, collaborator.id).catch(() => {});
        }
      }
      if (!ext) return res.status(404).json({ error: "No SIP extension found" });

      const ariSettingsList = await db.select().from(ariSettings).limit(1);
      if (!ariSettingsList.length || !ariSettingsList[0].username || !ariSettingsList[0].password) {
        return res.status(503).json({ error: "ARI credentials not configured" });
      }

      const { username, password, protocol: ariProtocol = "http" } = ariSettingsList[0];
      const authHeader = "Basic " + Buffer.from(`${username}:${password}`).toString("base64");
      const callLogId = req.params.id;
      const recordingName = `mobile_${callLogId}_${Date.now()}`;

      const servers = [
        { host: ASTERISK_SK_HOST, port: ASTERISK_SK_PORT },
        { host: ASTERISK_MEDIAGTW_HOST, port: ASTERISK_MEDIAGTW_PORT },
      ];

      let recordingStarted = false;
      let activeChannelId: string | null = null;

      for (const server of servers) {
        try {
          const baseUrl = `${ariProtocol}://${server.host}:${server.port}`;

          const channelsResp = await fetch(`${baseUrl}/ari/channels`, {
            headers: { Authorization: authHeader },
            signal: AbortSignal.timeout(3000),
          });
          if (!channelsResp.ok) continue;

          const channels: any[] = await channelsResp.json();
          const sipUser = (ext.sipUsername || ext.extension || '').toLowerCase();
          const channel = channels.find((ch: any) => {
            const chanName = (ch.name || '').toLowerCase();
            const endpoint = (ch.caller?.number || ch.connected?.number || '').toLowerCase();
            return chanName.includes(sipUser) || chanName.includes(ext.extension.toLowerCase()) || endpoint === ext.extension;
          });

          if (!channel) continue;
          activeChannelId = channel.id;

          let recordResp = await fetch(
            `${baseUrl}/ari/channels/${channel.id}/record?name=${encodeURIComponent(recordingName)}&format=wav&beep=false&ifExists=overwrite`,
            {
              method: "POST",
              headers: { Authorization: authHeader, "Content-Type": "application/json" },
              signal: AbortSignal.timeout(3000),
            }
          );

          if (recordResp.ok) {
            recordingStarted = true;
            console.log(`[ServerRecording] Started ARI recording '${recordingName}' on channel ${channel.id} at ${server.host}`);
            break;
          } else if (recordResp.status === 409) {
            // Channel is in dialplan (native bridge) — ARI can't record it directly.
            // Primary: AMI MixMonitor with bridge mode ('b') captures BOTH sides reliably.
            console.log(`[ServerRecording] Channel not in Stasis, trying AMI MixMonitor on '${channel.name}' (both sides)`);

            let amiRecorded = false;
            const amiRecordingPath = `/var/spool/asterisk/monitor/${recordingName}`;

            try {
              const sshPort = ariSettingsList[0].sshPort || 22;
              const sshUser = ariSettingsList[0].sshUsername;
              const sshPass = ariSettingsList[0].sshPassword;

              if (!sshUser || !sshPass) {
                throw new Error("SSH credentials not configured in ARI settings");
              }

              // Ensure recording directory exists on Asterisk server (silently created if missing)
              try {
                await runSshCommand(server.host, sshPort, sshUser, sshPass,
                  `mkdir -p /var/spool/asterisk/monitor && chown -R asterisk:asterisk /var/spool/asterisk/monitor 2>/dev/null; echo ok`
                );
              } catch (mkdirErr: any) {
                console.warn(`[ServerRecording] mkdir on Asterisk failed (non-fatal): ${mkdirErr?.message}`);
              }

              // SSH tunnel to AMI on localhost:5038 of Asterisk server — bypasses external firewall
              // NOTE: No 'b' option — without it MixMonitor immediately forces a software (mixing) bridge,
              // which guarantees both channel directions (read+write) are captured even when direct_media is negotiated.
              const amiResult = await sendAmiActionViaSshTunnel(
                server.host, sshPort, sshUser, sshPass,
                username, password,
                {
                  Action: "MixMonitor",
                  Channel: channel.name,
                  File: `${amiRecordingPath}.wav`,
                  Options: "v(1)V(1)",
                }
              );

              if (amiResult.success) {
                recordingStarted = true;
                amiRecorded = true;

                // Try to also attach MixMonitor to the TRUNK peer channel as a fallback.
                // When the mobile app uses DTLS-SRTP + OPUS (WebRTC), Asterisk may fail to
                // write audio to MixMonitor on the mobile leg without logging any error.
                // The trunk leg (PJSIP/trunk-ro-endpoint / trunk-sk-endpoint) uses plain
                // RTP with ulaw/alaw — no DTLS/OPUS complications — and will always have
                // audio if the remote party answered.
                // NOTE: BRIDGEPEER via AMI Getvar is unreliable in a native bridge context
                // (returns empty). Instead, we scan the ARI channels list (already fetched)
                // for a trunk channel, then attach MixMonitor directly via AMI.
                let amiTrunkFilePath: string | undefined;
                try {
                  const trunkChannel = channels.find((ch: any) => {
                    const name = (ch.name || '').toLowerCase();
                    return name.includes('trunk') && ch.id !== channel.id;
                  });
                  if (trunkChannel) {
                    amiTrunkFilePath = `${amiRecordingPath}_trunk`;
                    const trunkResult = await sendAmiActionViaSshTunnel(
                      server.host, sshPort, sshUser, sshPass,
                      username, password,
                      {
                        Action: "MixMonitor",
                        Channel: trunkChannel.name,
                        File: `${amiTrunkFilePath}.wav`,
                        Options: "v(1)V(1)",
                      }
                    );
                    if (trunkResult.success) {
                      console.log(`[ServerRecording] Also started MixMonitor on trunk peer '${trunkChannel.name}' → ${amiTrunkFilePath}.wav (DTLS fallback)`);
                    } else {
                      console.warn(`[ServerRecording] Trunk peer MixMonitor failed: ${trunkResult.response}`);
                      amiTrunkFilePath = undefined;
                    }
                  } else {
                    console.log(`[ServerRecording] No trunk channel found in ARI list (${channels.length} channels) — no fallback recording`);
                  }
                } catch (bridgePeerErr: any) {
                  console.warn(`[ServerRecording] Trunk peer detection non-fatal: ${(bridgePeerErr as any).message}`);
                }

                mobileActiveRecordings.set(callLogId, {
                  recordingName,
                  amiFilePath: amiRecordingPath,
                  amiTrunkFilePath,
                  sshHost: server.host,
                  sshPort,
                  sshUser,
                  sshPass,
                });
                console.log(`[ServerRecording] AMI MixMonitor (via SSH tunnel) started on '${channel.name}', file: ${amiRecordingPath}.wav — SSH download target: ${sshUser}@${server.host}:${sshPort} (both sides)`);
                break;
              } else {
                console.warn(`[ServerRecording] AMI MixMonitor via SSH tunnel failed: ${amiResult.response}`);
              }
            } catch (amiErr: any) {
              console.warn(`[ServerRecording] AMI SSH tunnel error: ${amiErr?.message} — falling back to ARI snoop`);
            }

            // Fallback: ARI snoop (captures at least one side via Stasis)
            if (!amiRecorded) {
              const snoopId = `snoop-${recordingName}`;
              const snoopResp = await fetch(
                `${baseUrl}/ari/channels/${channel.id}/snoop?spy=both&whisper=none&app=indexus-inbound&snoopId=${encodeURIComponent(snoopId)}`,
                {
                  method: "POST",
                  headers: { Authorization: authHeader, "Content-Type": "application/json" },
                  signal: AbortSignal.timeout(3000),
                }
              );
              if (snoopResp.ok) {
                const snoopChannel = await snoopResp.json();
                const snoopChanId = snoopChannel?.id;
                if (snoopChanId) {
                  await new Promise(r => setTimeout(r, 500));
                  const snoopRecResp = await fetch(
                    `${baseUrl}/ari/channels/${snoopChanId}/record?name=${encodeURIComponent(recordingName)}&format=wav&beep=false&ifExists=overwrite`,
                    {
                      method: "POST",
                      headers: { Authorization: authHeader, "Content-Type": "application/json" },
                      signal: AbortSignal.timeout(3000),
                    }
                  );
                  if (snoopRecResp.ok) {
                    recordingStarted = true;
                    console.log(`[ServerRecording] Snoop fallback recording started on snoop channel ${snoopChanId}`);
                    break;
                  } else {
                    const txt = await snoopRecResp.text().catch(() => "");
                    console.warn(`[ServerRecording] Snoop record failed (${snoopRecResp.status}): ${txt}`);
                  }
                }
              } else {
                const txt = await snoopResp.text().catch(() => "");
                console.warn(`[ServerRecording] Snoop creation failed (${snoopResp.status}): ${txt}`);
              }
            }
          } else {
            const txt = await recordResp.text().catch(() => "");
            console.warn(`[ServerRecording] ARI record failed (${recordResp.status}): ${txt}`);
          }
        } catch (e: any) {
          console.warn(`[ServerRecording] Server ${server.host} error: ${e?.message}`);
        }
      }

      res.json({
        success: recordingStarted,
        recordingName: recordingStarted ? recordingName : null,
        channelId: activeChannelId,
        message: recordingStarted
          ? "Server-side recording started via Asterisk ARI"
          : "Active channel not found — mic-only recording will be used",
      });
    } catch (error: any) {
      console.error("Trigger server recording error:", error);
      res.status(500).json({ error: "Failed to trigger server recording" });
    }
  });

  // Called by mobile when call ends — downloads AMI MixMonitor recording via SSH and saves to DB
  app.post("/api/mobile/call-log/:id/finalize-server-recording", async (req, res) => {
    try {
      const tokenData = await getMobileCollaboratorFromToken(req);
      if (!tokenData) return res.status(401).json({ error: "Unauthorized" });

      const callLogId = req.params.id;
      console.log(`[FinalizeRecording] Called for callLogId=${callLogId}, activeRecordings=${JSON.stringify([...mobileActiveRecordings.keys()])}`);
      const recInfo = mobileActiveRecordings.get(callLogId);
      if (!recInfo) {
        console.warn(`[FinalizeRecording] No recording found in Map for callLogId=${callLogId} — map has ${mobileActiveRecordings.size} entries`);
        return res.json({ success: false, message: "No active server recording found for this call" });
      }

      // Fetch call log early so we can log duration on failure
      const [callLog] = await db.select().from(callLogs).where(eq(callLogs.id, callLogId)).limit(1);
      const callDurationSec = callLog?.durationSeconds ?? null;

      let audioBuffer: Buffer | null = null;

      console.log(`[FinalizeRecording] Starting SSH download: ${recInfo.sshUser}@${recInfo.sshHost}:${recInfo.sshPort} path=${recInfo.amiFilePath}.* (call duration: ${callDurationSec ?? "unknown"}s)`);

      // Retry up to 6 times with 3s delay — MixMonitor flushes the file after hangup (may take a few seconds)
      for (let attempt = 1; attempt <= 6; attempt++) {
        if (attempt > 1) await new Promise(r => setTimeout(r, 3000));
        try {
          console.log(`[FinalizeRecording] SSH download attempt ${attempt}/6 for '${recInfo.amiFilePath}.*'`);
          audioBuffer = await downloadFileViaSsh(
            recInfo.sshHost, recInfo.sshPort, recInfo.sshUser, recInfo.sshPass,
            recInfo.amiFilePath
          );
          console.log(`[FinalizeRecording] SSH download succeeded on attempt ${attempt}: ${audioBuffer.length} bytes`);
          break;
        } catch (e: any) {
          console.log(`[FinalizeRecording] Attempt ${attempt}/6 failed — ${e?.message}`);
        }
      }

      mobileActiveRecordings.delete(callLogId);

      // If primary (mobile DTLS leg) recording failed, attempt trunk-leg fallback.
      // The trunk channel uses standard SRTP and always captures audio if the remote answered.
      if (!audioBuffer && recInfo.amiTrunkFilePath) {
        console.log(`[FinalizeRecording] Primary failed — trying trunk fallback: ${recInfo.amiTrunkFilePath}.*`);
        for (let attempt = 1; attempt <= 4; attempt++) {
          if (attempt > 1) await new Promise(r => setTimeout(r, 2000));
          try {
            audioBuffer = await downloadFileViaSsh(
              recInfo.sshHost, recInfo.sshPort, recInfo.sshUser, recInfo.sshPass,
              recInfo.amiTrunkFilePath
            );
            console.log(`[FinalizeRecording] Trunk fallback succeeded on attempt ${attempt}: ${audioBuffer.length} bytes`);
            break;
          } catch (e: any) {
            console.log(`[FinalizeRecording] Trunk fallback attempt ${attempt}/4 failed — ${e?.message}`);
          }
        }
        // Clean up trunk file regardless of success
        runSshCommand(recInfo.sshHost, recInfo.sshPort, recInfo.sshUser, recInfo.sshPass,
          `sudo rm -f "${recInfo.amiTrunkFilePath}.wav" "${recInfo.amiTrunkFilePath}^wav.raw" 2>/dev/null; echo ok`
        ).catch(() => {});
      }

      if (!audioBuffer) {
        const likelyCause = callDurationSec !== null && callDurationSec < 4
          ? `call was too short (${callDurationSec}s) — MixMonitor likely started after audio ended`
          : callDurationSec !== null
            ? `unknown — call was ${callDurationSec}s, likely DTLS/RTP issue on mobile leg (trunk fallback also unavailable)`
            : "unknown — call duration not recorded";
        try {
          const listing = await runSshCommand(
            recInfo.sshHost, recInfo.sshPort, recInfo.sshUser, recInfo.sshPass,
            `ls -la "${recInfo.amiFilePath}.wav" "${recInfo.amiFilePath}^wav.raw" 2>/dev/null; echo "---size check done"`,
          );
          console.warn(`[FinalizeRecording] ALL ATTEMPTS FAILED — likely cause: ${likelyCause}. File on Asterisk: ${listing.trim()}`);
        } catch {
          console.warn(`[FinalizeRecording] ALL ATTEMPTS FAILED — likely cause: ${likelyCause} (SSH diagnostic also failed)`);
        }
        return res.json({ success: false, message: "Recording file not available via SSH — mic recording will be used" });
      }
      const now = new Date();
      const dateStr = now.toISOString().slice(0, 10).replace(/-/g, "");
      const timeStr = now.toISOString().slice(11, 19).replace(/:/g, "");
      const filename = `server_${dateStr}_${timeStr}_${callLogId.substring(0, 8)}.wav`;
      const filePath = path.join(STORAGE_PATHS.callRecordings, filename);

      fs.mkdirSync(STORAGE_PATHS.callRecordings, { recursive: true });
      fs.writeFileSync(filePath, audioBuffer);

      await db.insert(callRecordings).values({
        callLogId,
        userId: callLog?.userId || tokenData.collaboratorId,
        customerId: callLog?.customerId || null,
        campaignId: callLog?.campaignId || null,
        filename,
        filePath,
        mimeType: "audio/wav",
        fileSizeBytes: audioBuffer.length,
        durationSeconds: callLog?.durationSeconds || null,
        phoneNumber: callLog?.phoneNumber || null,
        agentName: "Mobile Agent",
        direction: callLog?.direction || "outbound",
        analysisStatus: "pending",
      });

      const [savedRecording] = await db.select().from(callRecordings).where(eq(callRecordings.callLogId, callLogId)).orderBy(desc(callRecordings.createdAt)).limit(1);

      // Delete source files from Asterisk to free space (best-effort)
      const cleanupPaths = [recInfo.amiFilePath, ...(recInfo.amiTrunkFilePath ? [recInfo.amiTrunkFilePath] : [])];
      const cleanupCmd = cleanupPaths.flatMap(p =>
        [`"${p}.wav"`, `"${p}^wav.raw"`, `"${p}.raw"`, `"${p}.ulaw"`, `"${p}.gsm"`]
      ).join(" ");
      runSshCommand(recInfo.sshHost, recInfo.sshPort, recInfo.sshUser, recInfo.sshPass,
        `sudo rm -f ${cleanupCmd} 2>/dev/null; echo deleted`
      ).then(out => console.log(`[FinalizeRecording] Cleaned up Asterisk file(s): ${out.trim()}`))
       .catch(err => console.warn(`[FinalizeRecording] Cleanup failed: ${err?.message}`));

      // Trigger AI analysis + transcription in background (same as mic-upload path)
      if (savedRecording && process.env.OPENAI_API_KEY) {
        processCallRecordingAnalysis(savedRecording.id, filePath).catch(err => {
          console.error(`[FinalizeRecording] Background analysis failed:`, err.message);
        });
      }

      console.log(`[FinalizeRecording] Saved via SSH from ${recInfo.sshHost}: ${filename} (${audioBuffer.length} bytes) — BOTH SIDES`);
      return res.json({ success: true, filename, bytes: audioBuffer.length });
    } catch (error: any) {
      console.error("Finalize server recording error:", error);
      res.status(500).json({ error: "Failed to finalize server recording" });
    }
  });

  app.post("/api/mobile/call-recording", uploadMobileRecording.single("recording"), async (req, res) => {
    try {
      const tokenData = await getMobileCollaboratorFromToken(req);
      if (!tokenData) {
        return res.status(401).json({ error: "Unauthorized" });
      }

      if (!req.file) return res.status(400).json({ error: "No recording file uploaded" });

      const { callLogId, phoneNumber, direction, durationSeconds, customerName, customerId, agentName } = req.body;
      if (!callLogId) return res.status(400).json({ error: "callLogId is required" });

      const collaborator = await storage.getCollaborator(tokenData.collaboratorId);
      if (!collaborator) {
        return res.status(404).json({ error: "Collaborator not found" });
      }

      if (!collaborator.mobileCallRecording) {
        try {
          const fsSync = await import("fs");
          fsSync.unlinkSync(req.file.path);
        } catch (e) {}
        return res.status(403).json({ error: "Call recording is not enabled for this collaborator" });
      }

      const sanitizeFn = (s: string) => (s || "").replace(/[^a-zA-Z0-9áčďéíľĺňóôŕšťúýžÁČĎÉÍĽĹŇÓÔŔŠŤÚÝŽ_-]/g, "_").substring(0, 50);
      const now = new Date();
      const dateStr = now.toISOString().slice(0, 10).replace(/-/g, "");
      const timeStr = now.toISOString().slice(11, 19).replace(/:/g, "");
      const agentDisplay = agentName || `${collaborator.firstName}_${collaborator.lastName}`;
      const extForRename = req.file.mimetype === "audio/ogg" ? "ogg" : req.file.mimetype === "audio/mp4" || req.file.mimetype === "audio/m4a" ? "m4a" : "webm";
      const correctFilename = `mobile_${sanitizeFn(customerName || "neznamy_klient")}_${dateStr}_${timeStr}_${sanitizeFn(agentDisplay)}.${extForRename}`;

      if (req.file.filename !== correctFilename) {
        const oldPath = req.file.path;
        const newPath = path.join(path.dirname(oldPath), correctFilename);
        try {
          const fsSync = await import("fs");
          fsSync.renameSync(oldPath, newPath);
          req.file.filename = correctFilename;
          req.file.path = newPath;
        } catch (e) {
          console.warn("[MobileRecording] Could not rename file:", e);
        }
      }

      const recordingData = {
        callLogId: String(callLogId),
        userId: collaborator.id,
        customerId: customerId || null,
        campaignId: null,
        filename: req.file.filename,
        filePath: req.file.path,
        mimeType: req.file.mimetype,
        fileSizeBytes: req.file.size,
        durationSeconds: durationSeconds ? parseInt(durationSeconds) : null,
        customerName: customerName || null,
        agentName: agentDisplay,
        campaignName: null,
        phoneNumber: phoneNumber || null,
        analysisStatus: "pending",
        direction: direction || "outbound",
        inboundQueueId: null,
        inboundQueueName: null,
      };

      const [recording] = await db.insert(callRecordings).values(recordingData).returning();

      if (process.env.OPENAI_API_KEY) {
        processCallRecordingAnalysis(recording.id, req.file.path).catch(err => {
          console.error(`[MobileRecording] Background analysis failed:`, err.message);
        });
      }

      console.log(`[MobileRecording] Recording uploaded: ${recording.id} by collaborator ${collaborator.id}`);
      res.status(201).json(recording);
    } catch (error: any) {
      console.error("Mobile call recording upload error:", error);
      res.status(500).json({ error: error.message || "Failed to upload recording" });
    }
  });

