  // Get DOCX template content as text for visual editor
  app.get("/api/configurator/docx-templates/:id/content", requireAuth, async (req, res) => {
    try {
      const template = await storage.getDocxTemplate(req.params.id);
      if (!template) {
        return res.status(404).json({ error: "DOCX template not found" });
      }

      const filePath = path.join(process.cwd(), template.filePath);
      if (!fs.existsSync(filePath)) {
        return res.status(404).json({ error: "DOCX file not found on disk" });
      }

      const fileBuffer = fs.readFileSync(filePath);
      const fileContent = fs.readFileSync(filePath, "binary");
      const zip = new PizZip(fileContent);
      const docXml = zip.file("word/document.xml")?.asText() || "";

      const hasShading = docXml.includes('w:shd') || docXml.includes('w:color');

      let html = "";

      if (hasShading) {
        const getAttr = (xml: string, tag: string, attr: string): string => {
          const re = new RegExp(`<${tag}[^>]*\\s${attr}="([^"]*)"`, 'i');
          const m = xml.match(re);
          return m ? m[1] : "";
        };

        const extractText = (xml: string): string => {
          const texts: string[] = [];
          const tRe = /<w:t[^>]*>([^<]*)<\/w:t>/g;
          let tm;
          while ((tm = tRe.exec(xml)) !== null) texts.push(tm[1]);
          return texts.join("");
        };

        const parseRun = (runXml: string): string => {
          const text = extractText(runXml);
          if (!text) return "";
          let style = "";
          if (runXml.includes("<w:b/>") || runXml.includes('<w:b ')) style += "font-weight:bold;";
          if (runXml.includes("<w:i/>") || runXml.includes('<w:i ')) style += "font-style:italic;";
          if (runXml.includes("<w:u ")) style += "text-decoration:underline;";
          const colorM = runXml.match(/<w:color\s+w:val="([^"]*)"/);
          if (colorM && colorM[1] !== "auto") style += `color:#${colorM[1]};`;
          const szM = runXml.match(/<w:sz\s+w:val="(\d+)"/);
          if (szM) style += `font-size:${Math.round(parseInt(szM[1]) / 2)}px;`;
          const escaped = text.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
          return style ? `<span style="${style}">${escaped}</span>` : escaped;
        };

        const parsePara = (paraXml: string): string => {
          let pStyle = "";
          const alignM = paraXml.match(/<w:jc\s+w:val="([^"]*)"/);
          if (alignM) pStyle += `text-align:${alignM[1]};`;
          const spAfterM = paraXml.match(/<w:spacing[^>]*w:after="(\d+)"/);
          if (spAfterM) pStyle += `margin-bottom:${Math.round(parseInt(spAfterM[1]) / 20)}px;`;
          const runRe = /<w:r\b[^>]*>[\s\S]*?<\/w:r>/g;
          let runs = "";
          let rm;
          while ((rm = runRe.exec(paraXml)) !== null) runs += parseRun(rm[0]);
          const pBorderM = paraXml.match(/<w:pBdr>[\s\S]*?<\/w:pBdr>/);
          if (pBorderM) {
            const bottomM = pBorderM[0].match(/<w:bottom[^>]*w:color="([^"]*)"/);
            if (bottomM) pStyle += `border-bottom:2px solid #${bottomM[1]};padding-bottom:8px;`;
          }
          const styleAttr = pStyle ? ` style="${pStyle}"` : "";
          return `<p${styleAttr}>${runs || "&nbsp;"}</p>`;
        };

        const parseCell = (cellXml: string): string => {
          let style = "";
          const shdM = cellXml.match(/<w:shd[^>]*w:fill="([^"]*)"/);
          if (shdM && shdM[1] !== "auto") style += `background-color:#${shdM[1]};`;
          const vAlignM = cellXml.match(/<w:vAlign\s+w:val="([^"]*)"/);
          if (vAlignM) style += `vertical-align:${vAlignM[1]};`;
          const borderM = cellXml.match(/<w:tcBorders>[\s\S]*?<\/w:tcBorders>/);
          if (borderM) {
            const bottomB = borderM[0].match(/<w:bottom[^>]*w:sz="(\d+)"[^>]*w:color="([^"]*)"/);
            if (bottomB) style += `border-bottom:${Math.max(1, Math.round(parseInt(bottomB[1]) / 4))}px solid #${bottomB[2]};`;
          }
          style += "padding:8px 12px;";
          const paraRe = /<w:p\b[^>]*>[\s\S]*?<\/w:p>/g;
          let content = "";
          let pm;
          while ((pm = paraRe.exec(cellXml)) !== null) content += parsePara(pm[0]);
          return `<td style="${style}">${content || "&nbsp;"}</td>`;
        };

        const parseRow = (rowXml: string): string => {
          const cellRe = /<w:tc\b[^>]*>[\s\S]*?<\/w:tc>/g;
          let cells = "";
          let cm;
          while ((cm = cellRe.exec(rowXml)) !== null) cells += parseCell(cm[0]);
          return `<tr>${cells}</tr>`;
        };

        const parseTable = (tableXml: string): string => {
          const rowRe = /<w:tr\b[^>]*>[\s\S]*?<\/w:tr>/g;
          let rows = "";
          let rm;
          while ((rm = rowRe.exec(tableXml)) !== null) rows += parseRow(rm[0]);
          return `<table style="width:100%;border-collapse:collapse;margin-bottom:16px;">${rows}</table>`;
        };

        const bodyM = docXml.match(/<w:body>([\s\S]*)<\/w:body>/);
        if (bodyM) {
          const bodyContent = bodyM[1];
          const elementRe = /(<w:tbl\b[\s\S]*?<\/w:tbl>|<w:p\b[^>]*>[\s\S]*?<\/w:p>)/g;
          let em;
          while ((em = elementRe.exec(bodyContent)) !== null) {
            const el = em[0];
            if (el.startsWith("<w:tbl")) {
              html += parseTable(el);
            } else if (el.startsWith("<w:p")) {
              if (!el.includes("<w:sectPr")) {
                html += parsePara(el);
              }
            }
          }
        }
      }

      if (!html || html.trim() === "" || html.trim() === "<p>&nbsp;</p>") {
        const mammothResult = await mammoth.convertToHtml({ buffer: fileBuffer }, {
          styleMap: [
            "p[style-name='Title'] => h1:fresh",
            "p[style-name='Heading 1'] => h1:fresh",
            "p[style-name='Heading 2'] => h2:fresh",
            "p[style-name='Heading 3'] => h3:fresh",
          ],
          convertImage: mammoth.images.imgElement(function(image: any) {
            return image.read("base64").then(function(imageBuffer: string) {
              return { src: `data:${image.contentType};base64,${imageBuffer}` };
            });
          })
        });
        html = mammothResult.value || "";
      }

      if (!html || html.trim() === "") {
        const paragraphMatches = docXml.match(/<w:p[^>]*>[\s\S]*?<\/w:p>/g) || [];
        const paragraphs: string[] = [];
        for (const para of paragraphMatches) {
          const textMatches = para.match(/<w:t[^>]*>([^<]*)<\/w:t>/g) || [];
          const text = textMatches.map(t => t.replace(/<[^>]+>/g, "")).join("");
          paragraphs.push(text);
        }
        html = paragraphs.map(p => `<p>${p}</p>`).join("");
      }

      res.json({ 
        content: html,
        template: {
          id: template.id,
          name: template.name,
          description: template.description,
        }
      });
    } catch (error) {
      console.error("Failed to get DOCX template content:", error);
      res.status(500).json({ error: "Failed to get DOCX template content" });
    }
  });

  app.post("/api/configurator/docx-templates/:id/save-clean", requireAuth, async (req, res) => {
    try {
      const template = await storage.getDocxTemplate(req.params.id);
      if (!template) {
        return res.status(404).json({ error: "DOCX template not found" });
      }

      const { content } = req.body;
      if (!content || typeof content !== "string") {
        return res.status(400).json({ error: "Content is required" });
      }

      const HTMLtoDOCX = (await import("html-to-docx")).default;

      let normalizedHtml = content
        .replace(/class="ql-align-center"/g, 'style="text-align: center;"')
        .replace(/class="ql-align-right"/g, 'style="text-align: right;"')
        .replace(/class="ql-align-justify"/g, 'style="text-align: justify;"')
        .replace(/class="ql-indent-(\d+)"/g, (_, level) => `style="margin-left: ${parseInt(level) * 40}px;"`)
        .replace(/class="ql-size-small"/g, 'style="font-size: 10px;"')
        .replace(/class="ql-size-large"/g, 'style="font-size: 18px;"')
        .replace(/class="ql-size-huge"/g, 'style="font-size: 24px;"')
        .replace(/<br>/g, '<br/>');

      const fullHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body>${normalizedHtml}</body></html>`;

      const docxBuffer = await HTMLtoDOCX(fullHtml, null, {
        table: { row: { cantSplit: true } },
        footer: false,
        header: false,
        pageNumber: false,
        font: "Calibri",
        fontSize: 22,
        decodeUnicode: true,
      });

      const filePath = path.join(process.cwd(), template.filePath);
      const bufferData = Buffer.isBuffer(docxBuffer) ? docxBuffer : Buffer.from(docxBuffer as ArrayBuffer);
      fs.writeFileSync(filePath, bufferData);

      await storage.updateDocxTemplate(template.id, {
        updatedAt: new Date(),
      });

      res.json({ 
        success: true, 
        message: "Šablóna bola uložená s formátovaním",
        path: template.filePath 
      });
    } catch (error) {
      console.error("Failed to save DOCX template:", error);
      res.status(500).json({ error: "Failed to save DOCX template" });
    }
  });

  // Preview DOCX template as PDF with sample data
  app.get("/api/configurator/docx-templates/:id/preview-pdf", requireAuth, async (req, res) => {
    try {
      const template = await storage.getDocxTemplate(req.params.id);
      if (!template) {
        return res.status(404).json({ error: "DOCX template not found" });
      }

      const docxPath = path.join(process.cwd(), template.filePath);
      if (!fs.existsSync(docxPath)) {
        return res.status(404).json({ error: "DOCX template file not found" });
      }

      const content = fs.readFileSync(docxPath, "binary");
      const zip = new PizZip(content);

      const cleanXmlTags = (zipFile: PizZip) => {
        const files = ["word/document.xml", "word/header1.xml", "word/header2.xml", "word/footer1.xml", "word/footer2.xml"];
        for (const fileName of files) {
          const file = zipFile.file(fileName);
          if (file) {
            let xmlContent = file.asText();
            let result = "";
            let i = 0;
            while (i < xmlContent.length) {
              const openPos = xmlContent.indexOf("{{", i);
              if (openPos === -1) { result += xmlContent.substring(i); break; }
              result += xmlContent.substring(i, openPos);
              const closePos = xmlContent.indexOf("}}", openPos);
              if (closePos === -1) { result += xmlContent.substring(openPos); break; }
              const section = xmlContent.substring(openPos, closePos + 2);
              let textOnly = section.replace(/<[^>]+>/g, "");
              if (textOnly.startsWith("{{") && textOnly.endsWith("}}")) {
                textOnly = "{" + textOnly.slice(2, -2) + "}";
              }
              result += textOnly;
              i = closePos + 2;
            }
            xmlContent = result;
            result = "";
            i = 0;
            while (i < xmlContent.length) {
              const hashPos = xmlContent.indexOf("{#", i);
              const slashPos = xmlContent.indexOf("{/", i);
              const caretPos = xmlContent.indexOf("{^", i);
              const positions = [hashPos, slashPos, caretPos].filter(p => p !== -1);
              if (positions.length === 0) { result += xmlContent.substring(i); break; }
              const openPos = Math.min(...positions);
              result += xmlContent.substring(i, openPos);
              const closePos = xmlContent.indexOf("}", openPos + 2);
              if (closePos === -1) { result += xmlContent.substring(openPos); break; }
              const section2 = xmlContent.substring(openPos, closePos + 1);
              result += section2.replace(/<[^>]+>/g, "");
              i = closePos + 1;
            }
            xmlContent = result;
            result = "";
            const singleBracePattern = /\{(?![#/^])([^{}]*?)\}/g;
            let lastIndex = 0;
            let match;
            while ((match = singleBracePattern.exec(xmlContent)) !== null) {
              if (/<[^>]+>/.test(match[0])) {
                result += xmlContent.substring(lastIndex, match.index);
                result += match[0].replace(/<[^>]+>/g, "");
                lastIndex = match.index + match[0].length;
              }
            }
            result += xmlContent.substring(lastIndex);
            xmlContent = result;
            zipFile.file(fileName, xmlContent);
          }
        }
      };

      cleanXmlTags(zip);

      const doc = new Docxtemplater(zip, {
        paragraphLoop: true,
        linebreaks: true,
        parser: expressionParser,
        nullGetter() { return ""; },
      });

      const sampleData = {
        qrCodePayBySquare: "",
        qrCodeEpc: "",
        invoice: {
          number: "FV-2025-00042",
          date: "06.02.2025",
          dueDate: "20.02.2025",
          variableSymbol: "2025000042",
          subtotal: "890.00",
          vatRate: "20",
          vatAmount: "178.00",
          total: "1 068.00",
          currency: "EUR",
          type: "Faktúra",
        },
        customer: {
          firstName: "Ján",
          lastName: "Novák",
          fullName: "Ján Novák",
          companyName: "",
          email: "jan.novak@email.sk",
          phone: "+421 900 123 456",
          address: "Dubová 7",
          street: "Dubová 7",
          city: "Košice",
          postalCode: "040 01",
          country: "Slovensko",
          ico: "",
          dic: "",
          icDph: "",
        },
        billing: {
          companyName: "INDEXUS Medical s.r.o.",
          address: "Hlavná 15",
          city: "821 01 Bratislava",
          taxId: "12345678",
          vatId: "SK2023456789",
          bankName: "Tatra banka, a.s.",
          iban: "SK12 1100 0000 0012 3456 7890",
          swift: "TATRSKBX",
        },
        items: [
          { index: 1, name: "Odber pupočníkovej krvi", description: "Odber pupočníkovej krvi", quantity: 1, unit: "ks", unitPrice: "890.00", vatRate: "20", totalPrice: "890.00", currency: "EUR" },
        ],
      };

      try {
        doc.render(sampleData);
      } catch (renderErr: any) {
        console.error("[Preview] Template render error:", renderErr?.message);
        return res.status(400).json({ error: `Chyba v šablóne: ${renderErr?.message || "Neznáma chyba"}` });
      }

      const renderedZip = doc.getZip();
      const buf = renderedZip.generate({ type: "nodebuffer", compression: "DEFLATE" });

      const tempDir = path.join(process.cwd(), "uploads/temp");
      if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

      const tempDocxPath = path.join(tempDir, `preview-${template.id}-${Date.now()}.docx`);
      const tempPdfPath = tempDocxPath.replace(".docx", ".pdf");
      fs.writeFileSync(tempDocxPath, buf);

      const userProfile = `/tmp/libreoffice-preview-${Date.now()}-${Math.random().toString(36).slice(2)}`;
      try {
        execSync(
          `soffice --headless -env:UserInstallation=file://${userProfile} --convert-to pdf --outdir "${tempDir}" "${tempDocxPath}"`,
          { timeout: 60000, encoding: "utf8" }
        );
      } catch (convErr: any) {
        console.error("[Preview] LibreOffice conversion failed:", convErr?.message);
        try { fs.unlinkSync(tempDocxPath); } catch {}
        try { execSync(`rm -rf "${userProfile}"`, { timeout: 5000 }); } catch {}
        return res.status(500).json({ error: "Konverzia do PDF zlyhala. Skontrolujte šablónu." });
      } finally {
        try { execSync(`rm -rf "${userProfile}"`, { timeout: 5000 }); } catch {}
      }

      if (fs.existsSync(tempPdfPath)) {
        res.setHeader("Content-Type", "application/pdf");
        res.setHeader("Content-Disposition", "inline");
        fs.createReadStream(tempPdfPath).pipe(res);
        res.on("finish", () => {
          try { fs.unlinkSync(tempDocxPath); } catch {}
          try { fs.unlinkSync(tempPdfPath); } catch {}
        });
      } else {
        try { fs.unlinkSync(tempDocxPath); } catch {}
        res.status(500).json({ error: "PDF conversion failed" });
      }
    } catch (error) {
      console.error("Error previewing DOCX template:", error);
      res.status(500).json({ error: "Failed to preview DOCX template" });
    }
  });

