  app.get("/api/agent/scheduled-queue", requireAuth, async (req, res) => {
    try {
      const user = req.session.user!;
      const now = new Date();

      const scheduledContacts = await db
        .select({
          ccId: campaignContacts.id,
          ccCustomerId: campaignContacts.customerId,
          ccCampaignId: campaignContacts.campaignId,
          ccCallbackDate: campaignContacts.callbackDate,
          ccNotes: campaignContacts.notes,
          ccCallbackNote: campaignContacts.callbackNote,
          ccAssignedTo: campaignContacts.assignedTo,
          ccStatus: campaignContacts.status,
          ccContactType: campaignContacts.contactType,
          ccClinicId: campaignContacts.clinicId,
          ccHospitalId: campaignContacts.hospitalId,
          ccCollaboratorId: campaignContacts.collaboratorId,
          customerFirstName: customers.firstName,
          customerLastName: customers.lastName,
          customerPhone: customers.phone,
          customerEmail: customers.email,
          clinicName: clinics.name,
          clinicDoctorFirstName: clinics.doctorFirstName,
          clinicDoctorLastName: clinics.doctorLastName,
          clinicPhone: clinics.phone,
          clinicEmail: clinics.email,
          hospitalName: hospitals.name,
          hospitalPhone: hospitals.phone,
          hospitalEmail: hospitals.email,
          campaignName: campaigns.name,
          campaignChannel: campaigns.channel,
          campaignScript: campaigns.script,
          campaignSettings: campaigns.settings,
          ccCurrentStepId: campaignContacts.currentScriptStepId,
          ccDispositionCode: campaignContacts.dispositionCode,
          ccDispositionChecklistCodes: campaignContacts.dispositionChecklistCodes,
        })
        .from(campaignContacts)
        .leftJoin(customers, eq(campaignContacts.customerId, customers.id))
        .leftJoin(clinics, eq(campaignContacts.clinicId, clinics.id))
        .leftJoin(hospitals, eq(campaignContacts.hospitalId, hospitals.id))
        .innerJoin(campaigns, eq(campaignContacts.campaignId, campaigns.id))
        .where(
          and(
            eq(campaignContacts.status, "callback_scheduled"),
            isNotNull(campaignContacts.callbackDate),
            or(
              eq(campaignContacts.assignedTo, user.id),
              eq(campaignContacts.assignedTo, "all"),
              isNull(campaignContacts.assignedTo)
            )
          )
        );

      const scheduledSessions = await db
        .select({
          sessionId: campaignContactSessions.id,
          sessionCampaignContactId: campaignContactSessions.campaignContactId,
          sessionCallbackDate: campaignContactSessions.callbackDate,
          sessionNotes: campaignContactSessions.notes,
          sessionUserId: campaignContactSessions.userId,
          ccCustomerId: campaignContacts.customerId,
          ccCampaignId: campaignContacts.campaignId,
          ccContactType: campaignContacts.contactType,
          ccClinicId: campaignContacts.clinicId,
          ccHospitalId: campaignContacts.hospitalId,
          customerFirstName: customers.firstName,
          customerLastName: customers.lastName,
          customerPhone: customers.phone,
          customerEmail: customers.email,
          clinicName: clinics.name,
          clinicDoctorFirstName: clinics.doctorFirstName,
          clinicDoctorLastName: clinics.doctorLastName,
          clinicPhone: clinics.phone,
          clinicEmail: clinics.email,
          hospitalName: hospitals.name,
          hospitalPhone: hospitals.phone,
          hospitalEmail: hospitals.email,
          campaignName: campaigns.name,
          campaignChannel: campaigns.channel,
          campaignScript: campaigns.script,
          campaignSettings: campaigns.settings,
          ccCurrentStepId: campaignContacts.currentScriptStepId,
          ccDispositionCode: campaignContacts.dispositionCode,
          ccDispositionChecklistCodes: campaignContacts.dispositionChecklistCodes,
        })
        .from(campaignContactSessions)
        .innerJoin(campaignContacts, eq(campaignContactSessions.campaignContactId, campaignContacts.id))
        .leftJoin(customers, eq(campaignContacts.customerId, customers.id))
        .leftJoin(clinics, eq(campaignContacts.clinicId, clinics.id))
        .leftJoin(hospitals, eq(campaignContacts.hospitalId, hospitals.id))
        .innerJoin(campaigns, eq(campaignContacts.campaignId, campaigns.id))
        .where(
          and(
            eq(campaignContactSessions.callbackScheduled, true),
            isNotNull(campaignContactSessions.callbackDate),
            gte(campaignContactSessions.callbackDate, now),
            or(
              eq(campaignContactSessions.userId, user.id),
              eq(campaignContacts.assignedTo, "all")
            )
          )
        );

      const seenIds = new Set<string>();
      const items: any[] = [];

      const channelTypeMap: Record<string, string> = {
        phone: "callback",
        email: "email",
        sms: "sms",
        mixed: "callback",
      };

      function resolveStepInfo(scriptJson: string | null, stepId: string | null): { stepName: string | null; stepIndex: number | null } {
        if (!stepId || !scriptJson) return { stepName: null, stepIndex: null };
        try {
          const parsed = JSON.parse(scriptJson);
          if (parsed?.steps && Array.isArray(parsed.steps)) {
            const idx = parsed.steps.findIndex((s: any) => s.id === stepId);
            if (idx >= 0) return { stepName: parsed.steps[idx].title || `Step ${idx + 1}`, stepIndex: idx + 1 };
          }
        } catch {}
        return { stepName: null, stepIndex: null };
      }

      for (const row of scheduledContacts) {
        const key = `cc-${row.ccId}`;
        if (seenIds.has(key)) continue;
        seenIds.add(key);
        const contactType = row.ccContactType || "customer";
        let contactName = "";
        let contactPhone = "";
        let contactEmail = "";
        let contactId = row.ccCustomerId;
        if (contactType === "clinic") {
          contactName = row.clinicDoctorLastName 
            ? `${row.clinicDoctorFirstName || ""} ${row.clinicDoctorLastName}`.trim() + (row.clinicName ? ` (${row.clinicName})` : "")
            : row.clinicName || "";
          contactPhone = row.clinicPhone || "";
          contactEmail = row.clinicEmail || "";
          contactId = row.ccClinicId || row.ccCustomerId;
        } else if (contactType === "hospital") {
          contactName = row.hospitalName || "";
          contactPhone = row.hospitalPhone || "";
          contactEmail = row.hospitalEmail || "";
          contactId = row.ccHospitalId || row.ccCustomerId;
        } else {
          contactName = `${row.customerFirstName || ""} ${row.customerLastName || ""}`.trim();
          contactPhone = row.customerPhone || "";
          contactEmail = row.customerEmail || "";
        }
        const stepInfo = resolveStepInfo(row.campaignScript, row.ccCurrentStepId);
        items.push({
          id: row.ccId,
          type: channelTypeMap[row.campaignChannel || "phone"] || "callback",
          contactId,
          contactName,
          contactPhone,
          contactEmail,
          contactType,
          campaignId: row.ccCampaignId,
          campaignName: row.campaignName,
          scheduledAt: row.ccCallbackDate,
          notes: row.ccCallbackNote || row.ccNotes || "",
          status: "pending",
          stepName: stepInfo.stepName,
          stepIndex: stepInfo.stepIndex,
          dispositionCode: row.ccDispositionCode || null,
          dispositionChecklistCodes: (row.ccDispositionChecklistCodes as string[] | null) || [],
          campaignQueueDisplayMode: (() => { try { return row.campaignSettings ? (JSON.parse(row.campaignSettings).queueDisplayMode || null) : null; } catch { return null; } })(),
        });
      }

      for (const row of scheduledSessions) {
        const key = `session-${row.sessionId}`;
        if (seenIds.has(key)) continue;
        seenIds.add(key);
        const sContactType = row.ccContactType || "customer";
        let sContactName = "";
        let sContactPhone = "";
        let sContactEmail = "";
        let sContactId = row.ccCustomerId;
        if (sContactType === "clinic") {
          sContactName = row.clinicDoctorLastName 
            ? `${row.clinicDoctorFirstName || ""} ${row.clinicDoctorLastName}`.trim() + (row.clinicName ? ` (${row.clinicName})` : "")
            : row.clinicName || "";
          sContactPhone = row.clinicPhone || "";
          sContactEmail = row.clinicEmail || "";
          sContactId = row.ccClinicId || row.ccCustomerId;
        } else if (sContactType === "hospital") {
          sContactName = row.hospitalName || "";
          sContactPhone = row.hospitalPhone || "";
          sContactEmail = row.hospitalEmail || "";
          sContactId = row.ccHospitalId || row.ccCustomerId;
        } else {
          sContactName = `${row.customerFirstName || ""} ${row.customerLastName || ""}`.trim();
          sContactPhone = row.customerPhone || "";
          sContactEmail = row.customerEmail || "";
        }
        const sStepInfo = resolveStepInfo(row.campaignScript, row.ccCurrentStepId);
        items.push({
          id: row.sessionId,
          type: channelTypeMap[row.campaignChannel || "phone"] || "callback",
          contactId: sContactId,
          contactName: sContactName,
          contactPhone: sContactPhone,
          contactEmail: sContactEmail,
          contactType: sContactType,
          campaignId: row.ccCampaignId,
          campaignName: row.campaignName,
          scheduledAt: row.sessionCallbackDate,
          notes: row.sessionNotes || "",
          status: "pending",
          stepName: sStepInfo.stepName,
          stepIndex: sStepInfo.stepIndex,
          dispositionCode: row.ccDispositionCode || null,
          dispositionChecklistCodes: (row.ccDispositionChecklistCodes as string[] | null) || [],
          campaignQueueDisplayMode: (() => { try { return row.campaignSettings ? (JSON.parse(row.campaignSettings).queueDisplayMode || null) : null; } catch { return null; } })(),
        });
      }

      // Resolve disposition names and checklist names for queue items
      const queueCampaignIds = [...new Set((items as any[]).map(i => i.campaignId).filter(Boolean))];
      if (queueCampaignIds.length > 0) {
        const queueDispositions = await db.select().from(campaignDispositions)
          .where(inArray(campaignDispositions.campaignId, queueCampaignIds));
        const queueDispLookup = new Map<string, string>();
        for (const d of queueDispositions) {
          queueDispLookup.set(`${d.campaignId}::${d.code}`, d.name);
        }
        for (const item of items as any[]) {
          if (item.dispositionCode) {
            item.dispositionName = queueDispLookup.get(`${item.campaignId}::${item.dispositionCode}`) || null;
          }
          if (Array.isArray(item.dispositionChecklistCodes) && item.dispositionChecklistCodes.length > 0) {
            item.dispositionChecklistNames = item.dispositionChecklistCodes
              .map((code: string) => queueDispLookup.get(`${item.campaignId}::${code}`) || code);
          }
        }
      }

      items.sort((a, b) => new Date(a.scheduledAt).getTime() - new Date(b.scheduledAt).getTime());
      console.log(`[ScheduledQueue] User ${user.id}: ${scheduledContacts.length} contacts, ${scheduledSessions.length} sessions, ${items.length} total items`);
      res.json(items);
    } catch (error) {
      console.error("Failed to fetch scheduled queue:", error);
      res.status(500).json({ error: "Failed to fetch scheduled queue" });
    }
  });

