  // Upload external contacts for a campaign (CSV or Excel)
  app.post("/api/campaigns/:id/contacts/import", requireAuth, uploadContactsFile.single("file"), async (req, res) => {
    try {
      const campaign = await storage.getCampaign(req.params.id);
      if (!campaign) return res.status(404).json({ error: "Campaign not found" });

      const file = req.file;
      if (!file) return res.status(400).json({ error: "No file uploaded" });

      let rows: Record<string, string>[] = [];
      const ext = path.extname(file.originalname).toLowerCase();

      if (ext === ".csv" || ext === ".txt") {
        const content = file.buffer.toString("utf-8").replace(/^\uFEFF/, "");
        const separator = content.split("\n")[0]?.includes(";") ? ";" : ",";
        const workbook = XLSX.read(content, { type: "string", FS: separator, raw: true });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        if (!sheet) return res.status(400).json({ error: "Empty file" });
        rows = XLSX.utils.sheet_to_json<Record<string, string>>(sheet, { defval: "", raw: true });
        rows = rows.map(r => {
          const normalized: Record<string, string> = {};
          Object.entries(r).forEach(([k, v]) => {
            normalized[k.trim().toLowerCase()] = String(v).trim();
          });
          return normalized;
        });
      } else {
        const workbook = XLSX.read(file.buffer, { type: "buffer", raw: true });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        rows = XLSX.utils.sheet_to_json<Record<string, string>>(sheet, { defval: "", raw: true });
        rows = rows.map(r => {
          const normalized: Record<string, string> = {};
          Object.entries(r).forEach(([k, v]) => {
            normalized[k.trim().toLowerCase()] = String(v).trim();
          });
          return normalized;
        });
      }

      if (rows.length === 0) return res.status(400).json({ error: "No data rows found in file" });

      const contactType = req.body?.contactType || "customer";

      const fieldMap: Record<string, string[]> = {
        firstName: ["meno", "first_name", "firstname", "krstne_meno", "krstné_meno", "name", "lekar_meno"],
        lastName: ["priezvisko", "last_name", "lastname", "surname", "lekar_priezvisko"],
        phone: ["telefon", "telefón", "phone", "tel", "tel_1", "telefon_1"],
        phone2: ["telefon_2", "telefón_2", "phone_2", "tel_2", "mobile_2", "mobil"],
        email: ["email", "e-mail", "e_mail", "mail"],
        country: ["krajina", "country", "kraj", "land", "paese", "tara", "ország"],
        expectedDeliveryDate: ["datum_ocakavaneho_porodu", "dátum_očakávaného_pôrodu", "expected_delivery_date", "due_date", "termin_porodu", "termín_pôrodu"],
        extra1: ["extra_pole_1", "extra_1", "extra1", "poznamka", "poznámka", "note"],
        extra2: ["extra_pole_2", "extra_2", "extra2", "poznamka_2", "poznámka_2", "note_2"],
        name: ["nazov", "name", "název"],
        fullName: ["plny_nazov", "full_name", "plný_názov"],
        address: ["adresa", "address", "ulica_cislo", "street_number"],
        city: ["mesto", "city", "obec"],
        postalCode: ["psc", "postal_code", "psč"],
        contactPerson: ["kontaktna_osoba", "contact_person", "kontaktná_osoba"],
        website: ["web", "website", "www"],
        doctorTitle: ["lekar_titul", "doctor_title", "titul", "titul_pred", "title_before"],
        titleAfter: ["titul_za", "title_after"],
        collaboratorType: ["typ_spoluprace", "collaborator_type", "typ_spolupráce"],
      };

      function findField(row: Record<string, string>, candidates: string[]): string {
        for (const c of candidates) {
          if (row[c] !== undefined && row[c] !== "") return row[c];
        }
        return "";
      }

      const updateExisting = req.body?.updateExisting === "true" || req.body?.updateExisting === true;
      const results = { created: 0, updated: 0, skipped: 0, duplicates: 0, errors: [] as string[], importedContactIds: [] as string[] };
      const countryCode = campaign.countryCodes?.[0] || "SK";

      const existingCampaignContacts = await storage.getCampaignContacts(campaign.id);
      const existingCustomerIds = new Set(existingCampaignContacts.map(c => c.customerId));

      const allCustomers = await storage.getAllCustomers();
      const emailIndex = new Map<string, any>();
      const phoneIndex = new Map<string, any>();
      for (const c of allCustomers) {
        if (c.email) emailIndex.set(c.email.toLowerCase(), c);
        if (c.phone) phoneIndex.set(c.phone, c);
        if (c.mobile) phoneIndex.set(c.mobile, c);
        if (c.mobile2) phoneIndex.set(c.mobile2, c);
      }

      for (let i = 0; i < rows.length; i++) {
        const row = rows[i];
        const firstName = findField(row, fieldMap.firstName);
        const lastName = findField(row, fieldMap.lastName);
        const phone = findField(row, fieldMap.phone);
        const phone2 = findField(row, fieldMap.phone2);
        const email = findField(row, fieldMap.email);
        const country = findField(row, fieldMap.country);
        const expectedDate = findField(row, fieldMap.expectedDeliveryDate);
        const extra1 = findField(row, fieldMap.extra1);
        const extra2 = findField(row, fieldMap.extra2);
        const entityName = findField(row, fieldMap.name);
        const entityFullName = findField(row, fieldMap.fullName);
        const address = findField(row, fieldMap.address);
        const city = findField(row, fieldMap.city);
        const postalCode = findField(row, fieldMap.postalCode);
        const contactPerson = findField(row, fieldMap.contactPerson);
        const website = findField(row, fieldMap.website);
        const doctorTitle = findField(row, fieldMap.doctorTitle);
        const titleAfter = findField(row, fieldMap.titleAfter);
        const collaboratorType = findField(row, fieldMap.collaboratorType);

        const hasIdentifier = contactType === "customer" || contactType === "collaborator"
          ? (firstName || lastName)
          : entityName;

        if (!hasIdentifier) {
          results.skipped++;
          results.errors.push(`Riadok ${i + 2}: Chýba ${contactType === "customer" || contactType === "collaborator" ? "meno alebo priezvisko" : "názov"}`);
          continue;
        }

        try {
          if (contactType === "clinic") {
            const clinicData: any = {
              name: entityName || `${doctorTitle || ""} ${firstName} ${lastName}`.trim(),
              doctorName: `${doctorTitle || ""} ${firstName} ${lastName}`.trim() || null,
              doctorTitle: doctorTitle || null,
              doctorFirstName: firstName || null,
              doctorLastName: lastName || null,
              address: address || null,
              city: city || null,
              postalCode: postalCode || null,
              countryCode: country?.toUpperCase() || countryCode,
              phone: phone || null,
              email: email || null,
              website: website || null,
              notes: extra1 || null,
              isActive: true,
            };
            const clinic = await storage.createClinic(clinicData);

            const [newContact] = await storage.createCampaignContacts([{ campaignId: campaign.id, clinicId: clinic.id, contactType: "clinic", status: "pending", attemptCount: 0, priorityScore: 50 }]);
            if (newContact) results.importedContactIds.push(newContact.id);
            results.created++;

          } else if (contactType === "hospital") {
            const hospitalData: any = {
              name: entityName || "Nemocnica",
              fullName: entityFullName || entityName || null,
              streetNumber: address || null,
              city: city || null,
              postalCode: postalCode || null,
              countryCode: country?.toUpperCase() || countryCode,
              contactPerson: contactPerson || null,
              phone: phone || null,
              email: email || null,
              isActive: true,
              autoRecruiting: false,
              svetZdravia: false,
            };
            const hospital = await storage.createHospital(hospitalData);

            const [newContact] = await storage.createCampaignContacts([{ campaignId: campaign.id, hospitalId: hospital.id, contactType: "hospital", status: "pending", attemptCount: 0, priorityScore: 50 }]);
            if (newContact) results.importedContactIds.push(newContact.id);
            results.created++;

          } else if (contactType === "collaborator") {
            const collabData: any = {
              firstName: firstName || "Neznámy",
              lastName: lastName || "Neznámy",
              titleBefore: doctorTitle || null,
              titleAfter: titleAfter || null,
              phone: phone || null,
              mobile: phone2 || phone || null,
              email: email || null,
              countryCode: country?.toUpperCase() || countryCode,
              countryCodes: [country?.toUpperCase() || countryCode],
              collaboratorType: collaboratorType || null,
            };
            const collaborator = await storage.createCollaborator(collabData);

            const [newContact] = await storage.createCampaignContacts([{ campaignId: campaign.id, collaboratorId: collaborator.id, contactType: "collaborator", status: "pending", attemptCount: 0, priorityScore: 50 }]);
            if (newContact) results.importedContactIds.push(newContact.id);
            results.created++;

          } else {
            let existingCustomer: any = null;
            if (email && !email.includes("@noemail.local")) {
              existingCustomer = emailIndex.get(email.toLowerCase());
            }
            if (!existingCustomer && phone) {
              existingCustomer = phoneIndex.get(phone);
            }

            let customer;
            if (existingCustomer) {
              if (existingCustomerIds.has(existingCustomer.id)) {
                if (updateExisting) {
                  const updateData: any = {};
                  if (firstName) updateData.firstName = firstName;
                  if (lastName) updateData.lastName = lastName;
                  if (phone) { updateData.phone = phone; updateData.mobile = phone; }
                  if (phone2) updateData.mobile2 = phone2;
                  if (country) updateData.country = country.toUpperCase();
                  if (Object.keys(updateData).length > 0) {
                    await storage.updateCustomer(existingCustomer.id, updateData);
                    results.updated++;
                  } else {
                    results.duplicates++;
                  }
                  continue;
                }
                results.duplicates++;
                results.errors.push(`Riadok ${i + 2}: ${firstName} ${lastName} - už je v kampani`);
                continue;
              }
              if (updateExisting) {
                const updateData: any = {};
                if (firstName) updateData.firstName = firstName;
                if (lastName) updateData.lastName = lastName;
                if (phone) { updateData.phone = phone; updateData.mobile = phone; }
                if (phone2) updateData.mobile2 = phone2;
                if (country) updateData.country = country.toUpperCase();
                if (Object.keys(updateData).length > 0) {
                  await storage.updateCustomer(existingCustomer.id, updateData);
                  results.updated++;
                }
              }
              customer = existingCustomer;
            } else {
              const customerData: any = {
                firstName: firstName || "Neznámy",
                lastName: lastName || "Neznámy",
                phone: phone || null,
                mobile: phone || null,
                mobile2: phone2 || null,
                email: email || `import-${Date.now()}-${i}@noemail.local`,
                country: country?.toUpperCase() || countryCode,
                status: "active",
                clientStatus: "potential",
                leadStatus: "cold",
                leadScore: 0,
                newsletter: false,
                useCorrespondenceAddress: false,
                notes: [
                  extra1 ? `Extra 1: ${extra1}` : "",
                  extra2 ? `Extra 2: ${extra2}` : "",
                  expectedDate ? `Očakávaný dátum pôrodu: ${expectedDate}` : "",
                  `Importovaný z kampane: ${campaign.name}`,
                ].filter(Boolean).join("\n"),
              };

              if (expectedDate) {
                try {
                  let parsed: Date | null = null;
                  const ddmmyyyy = expectedDate.match(/^(\d{1,2})[.\/\-](\d{1,2})[.\/\-](\d{4})$/);
                  const yyyymmdd = expectedDate.match(/^(\d{4})[.\/\-](\d{1,2})[.\/\-](\d{1,2})$/);
                  if (ddmmyyyy) {
                    parsed = new Date(parseInt(ddmmyyyy[3]), parseInt(ddmmyyyy[2]) - 1, parseInt(ddmmyyyy[1]));
                  } else if (yyyymmdd) {
                    parsed = new Date(parseInt(yyyymmdd[1]), parseInt(yyyymmdd[2]) - 1, parseInt(yyyymmdd[3]));
                  }
                  if (parsed && !isNaN(parsed.getTime()) && parsed.getFullYear() > 1900 && parsed.getFullYear() < 2100) {
                    customerData.dateOfBirth = parsed;
                  }
                } catch {}
              }

              customer = await storage.createCustomer(customerData);
              if (customer.email) emailIndex.set(customer.email.toLowerCase(), customer);
              if (customer.phone) phoneIndex.set(customer.phone, customer);
              if (customer.mobile) phoneIndex.set(customer.mobile, customer);
            }

            existingCustomerIds.add(customer.id);
            const [newContact] = await storage.createCampaignContacts([{ campaignId: campaign.id, customerId: customer.id, status: "pending", attemptCount: 0, priorityScore: 50 }]);
            if (newContact) results.importedContactIds.push(newContact.id);
            results.created++;
          }
        } catch (err: any) {
          results.errors.push(`Riadok ${i + 2}: ${err.message || "Neznáma chyba"}`);
          results.skipped++;
        }
      }

      await logActivity(
        req.session.user!.id,
        "imported_external_contacts",
        "campaign",
        campaign.id,
        campaign.name,
        { created: results.created, skipped: results.skipped, duplicates: results.duplicates, total: rows.length },
        req.ip
      );

      res.json(results);
    } catch (error: any) {
      console.error("Failed to import contacts:", error);
      res.status(500).json({ error: error.message || "Failed to import contacts" });
    }
  });

  // Delete imported contacts batch (undo last import)
  app.post("/api/campaigns/:id/contacts/delete-batch", requireAuth, async (req, res) => {
    try {
      const campaign = await storage.getCampaign(req.params.id);
      if (!campaign) return res.status(404).json({ error: "Campaign not found" });

      const { contactIds } = req.body;
      if (!Array.isArray(contactIds) || contactIds.length === 0) {
        return res.status(400).json({ error: "No contact IDs provided" });
      }

      const campaignContacts = await storage.getCampaignContacts(campaign.id);
      const validIds = new Set(campaignContacts.map(c => c.id));

      let deleted = 0;
      for (const id of contactIds) {
        if (!validIds.has(id)) continue;
        const success = await storage.deleteCampaignContact(id);
        if (success) deleted++;
      }

      await logActivity(
        req.session.user!.id,
        "deleted_imported_contacts",
        "campaign",
        campaign.id,
        campaign.name,
        { deleted, total: contactIds.length },
        req.ip
      );

      res.json({ deleted });
    } catch (error: any) {
      console.error("Failed to delete imported contacts:", error);
      res.status(500).json({ error: error.message || "Failed to delete contacts" });
    }
  });

  // Script Templates CRUD
  app.get("/api/script-templates", requireAuth, async (req, res) => {
    try {
      const results = await db.select().from(scriptTemplates).orderBy(desc(scriptTemplates.updatedAt));
      res.json(results);
    } catch (error: any) {
      console.error("Error fetching script templates:", error);
      res.status(500).json({ error: "Failed to fetch script templates" });
    }
  });

  app.post("/api/script-templates", requireAuth, async (req, res) => {
    try {
      const { name, description, scriptData, tags, color } = req.body;
      if (!name || !scriptData) return res.status(400).json({ error: "Name and scriptData required" });
      const [template] = await db.insert(scriptTemplates).values({
        name,
        description: description || null,
        scriptData: typeof scriptData === "string" ? scriptData : JSON.stringify(scriptData),
        tags: tags || [],
        color: color || "gray",
        createdBy: (req as any).user?.id || null,
      }).returning();
      res.json(template);
    } catch (error: any) {
      console.error("Error creating script template:", error);
      res.status(500).json({ error: "Failed to create script template" });
    }
  });

  app.patch("/api/script-templates/:id", requireAuth, async (req, res) => {
    try {
      const { name, description, scriptData, tags, color } = req.body;
      const updateData: any = { updatedAt: new Date() };
      if (name !== undefined) updateData.name = name;
      if (description !== undefined) updateData.description = description;
      if (scriptData !== undefined) updateData.scriptData = typeof scriptData === "string" ? scriptData : JSON.stringify(scriptData);
      if (tags !== undefined) updateData.tags = tags;
      if (color !== undefined) updateData.color = color;
      const [template] = await db.update(scriptTemplates).set(updateData).where(eq(scriptTemplates.id, req.params.id)).returning();
      if (!template) return res.status(404).json({ error: "Template not found" });
      res.json(template);
    } catch (error: any) {
      console.error("Error updating script template:", error);
      res.status(500).json({ error: "Failed to update script template" });
    }
  });

  app.delete("/api/script-templates/:id", requireAuth, async (req, res) => {
    try {
      const [deleted] = await db.delete(scriptTemplates).where(eq(scriptTemplates.id, req.params.id)).returning();
      if (!deleted) return res.status(404).json({ error: "Template not found" });
      res.json({ success: true });
    } catch (error: any) {
      console.error("Error deleting script template:", error);
      res.status(500).json({ error: "Failed to delete script template" });
    }
  });

