  const COUNTRY_LANG_MAP: Record<string, string> = { SK: "sk", CZ: "cs", HU: "hu", RO: "ro", AT: "de", IT: "it", DE: "de" };

  const COUNTRY_NAME_MAP: Record<string, Record<string, string>> = {
    SK: { sk: "Slovensko", cs: "Slovensko", ro: "Slovacia", hu: "Szlov\u00e1kia", it: "Slovacchia", de: "Slowakei", en: "Slovakia" },
    CZ: { sk: "\u010cesko", cs: "\u010cesko", ro: "Cehia", hu: "Csehorsz\u00e1g", it: "Repubblica Ceca", de: "Tschechien", en: "Czech Republic" },
    HU: { sk: "Ma\u010farsko", cs: "Ma\u010farsko", ro: "Ungaria", hu: "Magyarorsz\u00e1g", it: "Ungheria", de: "Ungarn", en: "Hungary" },
    RO: { sk: "Rumunsko", cs: "Rumunsko", ro: "Rom\u00e2nia", hu: "Rom\u00e1nia", it: "Romania", de: "Rum\u00e4nien", en: "Romania" },
    AT: { sk: "Rak\u00fasko", cs: "Rakousko", ro: "Austria", hu: "Ausztria", it: "Austria", de: "\u00d6sterreich", en: "Austria" },
    IT: { sk: "Taliansko", cs: "It\u00e1lie", ro: "Italia", hu: "Olaszorsz\u00e1g", it: "Italia", de: "Italien", en: "Italy" },
    DE: { sk: "Nemecko", cs: "N\u011bmecko", ro: "Germania", hu: "N\u00e9metorsz\u00e1g", it: "Germania", de: "Deutschland", en: "Germany" },
  };

  const COUNTRY_FLAG_MAP: Record<string, string> = { SK: "\ud83c\uddf8\ud83c\uddf0", CZ: "\ud83c\udde8\ud83c\uddff", HU: "\ud83c\udded\ud83c\uddfa", RO: "\ud83c\uddf7\ud83c\uddf4", AT: "\ud83c\udde6\ud83c\uddf9", IT: "\ud83c\uddee\ud83c\uddf9", DE: "\ud83c\udde9\ud83c\uddea" };

  const renderOnboardingEmail = async (user: any, baseUrl: string) => {
    const fs = await import("fs");
    const path = await import("path");
    const templatePath = path.default.join(process.cwd(), "client", "public", "email-templates", "welcome-onboarding.html");
    let html = fs.default.readFileSync(templatePath, "utf-8");

    const countries = user.assignedCountries || [];
    const countryCode = countries[0] || "SK";
    const lang = countries.length > 1 ? "en" : (COUNTRY_LANG_MAP[countryCode] || "en");
    const t = ONBOARDING_I18N[lang] || ONBOARDING_I18N.en;

    const countryName = COUNTRY_NAME_MAP[countryCode]?.[lang] || countryCode;
    const countryFlag = COUNTRY_FLAG_MAP[countryCode] || "\ud83c\udff3\ufe0f";

    const isMs365 = (user as any).authMethod === "ms365";
    const tempPassword = isMs365 ? "\u2014" : "********";

    if (isMs365) {
      html = html.replace(/<!-- IF_LOCAL -->[\s\S]*?<!-- ENDIF_LOCAL -->/g, "");
      html = html.replace(/<!-- IF_MS365 -->/g, "").replace(/<!-- ENDIF_MS365 -->/g, "");
    } else {
      html = html.replace(/<!-- IF_MS365 -->[\s\S]*?<!-- ENDIF_MS365 -->/g, "");
      html = html.replace(/<!-- IF_LOCAL -->/g, "").replace(/<!-- ENDIF_LOCAL -->/g, "");
    }

    const loginUsername = user.username || user.email;
    const loginUrlWithUser = `${baseUrl}?user=${encodeURIComponent(loginUsername)}`;

    for (const [key, value] of Object.entries(t)) {
      html = html.replace(new RegExp(`\\{\\{t_${key}\\}\\}`, "g"), value);
    }

    return html
      .replace(/\{\{userName\}\}/g, user.fullName || user.username)
      .replace(/\{\{userEmail\}\}/g, user.email)
      .replace(/\{\{username\}\}/g, loginUsername)
      .replace(/\{\{tempPassword\}\}/g, tempPassword)
      .replace(/\{\{loginUrlWithUser\}\}/g, loginUrlWithUser)
      .replace(/\{\{loginUrl\}\}/g, baseUrl)
      .replace(/\{\{countryName\}\}/g, countryName)
      .replace(/\{\{countryFlag\}\}/g, countryFlag);
  };

  const getOnboardingEmailLang = (user: any): string => {
    const countries = user.assignedCountries || [];
    const countryCode = countries[0] || "SK";
    return countries.length > 1 ? "en" : (COUNTRY_LANG_MAP[countryCode] || "en");
  };

  app.post("/api/users/:id/onboarding-email/preview", requireAuth, async (req, res) => {
    try {
      const sessionUser = req.session.user;
      if (!sessionUser || (sessionUser.role !== "admin" && sessionUser.role !== "manager")) {
        return res.status(403).json({ error: "Insufficient permissions" });
      }

      const user = await storage.getUser(req.params.id);
      if (!user) return res.status(404).json({ error: "User not found" });

      const baseUrl = `${req.protocol}://${req.get("host")}`;
      const rendered = await renderOnboardingEmail(user, baseUrl);
      const lang = getOnboardingEmailLang(user);
      const t = ONBOARDING_I18N[lang] || ONBOARDING_I18N.en;

      res.json({ html: rendered, to: user.email, subject: `${t.emailSubjectPrefix}, ${user.fullName || user.username}` });
    } catch (error) {
      console.error("Error previewing onboarding email:", error);
      res.status(500).json({ error: "Failed to preview onboarding email" });
    }
  });

  app.post("/api/users/:id/onboarding-email/send", requireAuth, async (req, res) => {
    try {
      const sessionUser = req.session.user;
      if (!sessionUser || (sessionUser.role !== "admin" && sessionUser.role !== "manager")) {
        return res.status(403).json({ error: "Insufficient permissions" });
      }

      const user = await storage.getUser(req.params.id);
      if (!user) return res.status(404).json({ error: "User not found" });

      const baseUrl = `${req.protocol}://${req.get("host")}`;
      const rendered = await renderOnboardingEmail(user, baseUrl);
      const lang = getOnboardingEmailLang(user);
      const t = ONBOARDING_I18N[lang] || ONBOARDING_I18N.en;
      const subject = `${t.emailSubjectPrefix}, ${user.fullName || user.username}`;

      const countries = (user as any).assignedCountries || [];
      const countryCode = countries[0] || "SK";

      let sent = false;
      const systemConnection = await storage.getSystemMs365Connection(countryCode);
      if (systemConnection && systemConnection.isConnected) {
        try {
          const { getValidAccessToken, sendEmail: sendMs365Email } = await import("./lib/ms365");
          const { decryptTokenSafe, encryptTokenWithMarker } = await import("./lib/token-crypto");
          const decryptedAccessToken = systemConnection.accessToken ? decryptTokenSafe(systemConnection.accessToken) : null;
          const decryptedRefreshToken = systemConnection.refreshToken ? decryptTokenSafe(systemConnection.refreshToken) : null;
          const tokenResult = await getValidAccessToken(decryptedAccessToken, systemConnection.tokenExpiresAt, decryptedRefreshToken);
          if (tokenResult) {
            if (tokenResult.refreshed) {
              await storage.updateSystemMs365Connection(countryCode, {
                accessToken: encryptTokenWithMarker(tokenResult.accessToken),
                refreshToken: tokenResult.refreshToken ? encryptTokenWithMarker(tokenResult.refreshToken) : systemConnection.refreshToken,
                tokenExpiresAt: tokenResult.expiresOn
              });
            }
            await sendMs365Email(tokenResult.accessToken, [user.email], subject, rendered, true);
            sent = true;
            console.log(`[OnboardingEmail] Sent via system MS365 (${systemConnection.email}) for ${countryCode} to ${user.email}`);
          }
        } catch (ms365Err) {
          console.warn(`[OnboardingEmail] System MS365 for ${countryCode} failed:`, ms365Err);
        }
      }

      if (!sent) {
        const { sendEmail } = await import("./email");
        const success = await sendEmail({ to: user.email, subject, html: rendered });
        if (!success) {
          return res.status(500).json({ error: "Failed to send email" });
        }
        console.log(`[OnboardingEmail] Sent via SendGrid fallback to ${user.email}`);
      }

      await logActivity(
        sessionUser.id,
        "onboarding_email_sent",
        "user",
        req.params.id,
        `Onboarding email sent to ${user.email}`,
        null
      );

      res.json({ success: true, message: `Onboarding email sent to ${user.email}` });
    } catch (error) {
      console.error("Error sending onboarding email:", error);
      res.status(500).json({ error: "Failed to send onboarding email" });
    }
  });

  // ============================================
  // CONTRACT MANAGEMENT ENDPOINTS
  // ============================================

  app.get("/api/contracts/stats", requireAuth, async (req, res) => {
    try {
      const country = req.query.country as string | undefined;
      const countries = req.query.countries ? (req.query.countries as string).split(",").filter(Boolean) : undefined;
      const stats = await storage.getContractInstanceStats(country || undefined, countries);
      res.json(stats);
    } catch (error) {
      console.error("Error fetching contract stats:", error);
      res.status(500).json({ error: "Failed to fetch contract stats" });
    }
  });

  // Contract Categories
  app.get("/api/contracts/categories", requireAuth, async (req, res) => {
    try {
      const categories = await storage.getAllContractCategories();
      res.json(categories);
    } catch (error) {
      console.error("Error fetching contract categories:", error);
      res.status(500).json({ error: "Failed to fetch contract categories" });
    }
  });

  app.get("/api/contracts/categories/:id", requireAuth, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const category = await storage.getContractCategory(id);
      if (!category) {
        return res.status(404).json({ error: "Category not found" });
      }
      res.json(category);
    } catch (error) {
      console.error("Error fetching contract category:", error);
      res.status(500).json({ error: "Failed to fetch contract category" });
    }
  });

  app.post("/api/contracts/categories", requireAuth, async (req, res) => {
    try {
      const { value, label, description, sortOrder, labelSk, labelCz, labelHu, labelRo, labelIt, labelDe, labelUs } = req.body;
      
      // Check if value already exists
      const existing = await storage.getContractCategoryByValue(value);
      if (existing) {
        return res.status(400).json({ error: "Category with this value already exists" });
      }
      
      const category = await storage.createContractCategory({
        value,
        label,
        description: description || null,
        sortOrder: sortOrder || 0,
        labelSk: labelSk || null,
        labelCz: labelCz || null,
        labelHu: labelHu || null,
        labelRo: labelRo || null,
        labelIt: labelIt || null,
        labelDe: labelDe || null,
        labelUs: labelUs || null,
      });
      res.status(201).json(category);
    } catch (error) {
      console.error("Error creating contract category:", error);
      res.status(500).json({ error: "Failed to create contract category" });
    }
  });

  app.patch("/api/contracts/categories/:id", requireAuth, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const { value, label, description, sortOrder, labelSk, labelCz, labelHu, labelRo, labelIt, labelDe, labelUs } = req.body;
      
      // Check if value already exists for another category
      if (value) {
        const existing = await storage.getContractCategoryByValue(value);
        if (existing && existing.id !== id) {
          return res.status(400).json({ error: "Category with this value already exists" });
        }
      }
      
      const category = await storage.updateContractCategory(id, {
        ...(value && { value }),
        ...(label && { label }),
        ...(description !== undefined && { description }),
        ...(sortOrder !== undefined && { sortOrder }),
        ...(labelSk !== undefined && { labelSk: labelSk || null }),
        ...(labelCz !== undefined && { labelCz: labelCz || null }),
        ...(labelHu !== undefined && { labelHu: labelHu || null }),
        ...(labelRo !== undefined && { labelRo: labelRo || null }),
        ...(labelIt !== undefined && { labelIt: labelIt || null }),
        ...(labelDe !== undefined && { labelDe: labelDe || null }),
        ...(labelUs !== undefined && { labelUs: labelUs || null }),
      });
      
      if (!category) {
        return res.status(404).json({ error: "Category not found" });
      }
      res.json(category);
    } catch (error) {
      console.error("Error updating contract category:", error);
      res.status(500).json({ error: "Failed to update contract category" });
    }
  });

