  app.post("/api/contracts", requireAuth, async (req, res) => {
    try {
      const { categoryId, customerId, billingDetailsId, currency, notes, templateVersionId, numberRangeId } = req.body;
      
      if (!categoryId) {
        return res.status(400).json({ error: "Vyberte typ zmluvy (kategóriu)" });
      }
      
      if (!customerId) {
        return res.status(400).json({ error: "Vyberte zákazníka" });
      }
      
      if (!billingDetailsId) {
        return res.status(400).json({ error: "Vyberte fakturačnú spoločnosť" });
      }
      
      // Get customer to determine country
      const customer = await storage.getCustomer(customerId);
      if (!customer) {
        return res.status(400).json({ error: "Zákazník nebol nájdený" });
      }
      
      const countryCode = customer.country || "SK";
      
      // Find template for category and country
      const categoryDefaultTemplate = await storage.getCategoryDefaultTemplate(parseInt(categoryId), countryCode);
      if (!categoryDefaultTemplate) {
        // Get category name for better error message
        const category = await storage.getContractCategory(parseInt(categoryId));
        const categoryName = category?.label || categoryId;
        return res.status(400).json({ 
          error: `Pre kategóriu "${categoryName}" a krajinu "${countryCode}" neexistuje šablóna zmluvy. Najprv vytvorte šablónu v nastaveniach zmlúv.` 
        });
      }
      
      // Use the category default template ID as the template reference
      const templateId = String(categoryDefaultTemplate.id);
      
      // Generate contract number from number range if provided, otherwise use legacy method
      let contractNumber: string;
      if (numberRangeId) {
        const range = await storage.getNumberRange(numberRangeId);
        if (!range) {
          return res.status(404).json({ error: "Číselník nebol nájdený" });
        }
        if (!range.isActive) {
          return res.status(400).json({ error: "Číselník nie je aktívny" });
        }
        if (range.type !== "contract") {
          return res.status(400).json({ error: "Vybraný číselník nie je typu zmluva" });
        }
        if (range.countryCode && range.countryCode !== countryCode) {
          return res.status(400).json({ error: "Vybraný číselník nie je pre krajinu zákazníka" });
        }
        const result = await storage.generateNextNumber(numberRangeId);
        if (!result) {
          return res.status(409).json({ error: "Číselník je vyčerpaný alebo nastala chyba, skúste to znova" });
        }
        contractNumber = result.invoiceNumber;
        console.log(`[Contract] Generated number from range ${numberRangeId}: ${contractNumber}`);
      } else {
        contractNumber = await storage.getNextContractNumber(req.body.prefix || "ZML");
      }
      
      const data = insertContractInstanceSchema.parse({
        templateId,
        templateVersionId: templateVersionId || null,
        customerId,
        billingDetailsId,
        currency: currency || "EUR",
        notes: notes || null,
        contractNumber,
        createdBy: req.session.user!.id,
        contactDate: new Date(),
        createdContractDate: new Date()
      });
      
      const contract = await storage.createContractInstance(data);
      
      await storage.createContractAuditLog({
        contractId: contract.id,
        action: "created",
        actorId: req.session.user!.id,
        actorType: "user",
        actorName: req.session.user!.fullName,
        actorEmail: req.session.user!.email,
        ipAddress: req.ip,
        userAgent: req.headers["user-agent"] || null,
        details: JSON.stringify({ status: "draft", categoryId: parseInt(categoryId), countryCode })
      });
      
      await logActivity(req.session.user!.id, "create", "contract", contract.id, contract.contractNumber, null, req.ip);

      // Emit automation event for new contract
      try {
        const { emitEntityCreated } = await import("./lib/event-bus");
        await emitEntityCreated("contract", "contract", contract.id, contract, req.session.user!.id, customer?.country || null);
      } catch (err) { console.error("[EventBus] contract create emit error:", err); }

      // Auto-generate PDF after contract creation
      try {
        const hasDocxTemplate = categoryDefaultTemplate.sourceDocxPath && 
          fs.existsSync(path.join(process.cwd(), categoryDefaultTemplate.sourceDocxPath));
        
        if (hasDocxTemplate) {
          const docxPath = path.join(process.cwd(), categoryDefaultTemplate.sourceDocxPath!);
          const billingDetails = billingDetailsId ? await storage.getBillingDetailsById(String(billingDetailsId)) : null;
          
          // Build variables for DOCX template
          const docxData: Record<string, string> = {
            "customer.fullName": `${customer.firstName || ""} ${customer.lastName || ""}`.trim(),
            "customer.firstName": customer.firstName || "",
            "customer.lastName": customer.lastName || "",
            "customer.email": customer.email || "",
            "customer.phone": customer.phone || "",
            "customer.address": customer.address || "",
            "customer.permanentAddress": customer.address || "",
            "customer.city": customer.city || "",
            "customer.postalCode": customer.postalCode || "",
            "customer.dateOfBirth": customer.dateOfBirth ? new Date(customer.dateOfBirth).toLocaleDateString("sk-SK") : "",
            "customer.birthDate": customer.dateOfBirth ? new Date(customer.dateOfBirth).toLocaleDateString("sk-SK") : "",
            "customer.birthNumber": customer.nationalId || "",
            "customer.date": new Date().toLocaleDateString("sk-SK"),
            "customer.correspondenceAddress": customer.address || "",
            "mother.permanentAddress": customer.address || "",
            "mother.birthDate": customer.dateOfBirth ? new Date(customer.dateOfBirth).toLocaleDateString("sk-SK") : "",
            "mother.fullName": `${customer.firstName || ""} ${customer.lastName || ""}`.trim(),
            "billing.companyName": billingDetails?.companyName || "",
            "billing.ico": billingDetails?.ico || "",
            "billing.dic": billingDetails?.dic || "",
            "billing.vatNumber": billingDetails?.vatNumber || "",
            "billing.address": billingDetails?.address || billingDetails?.residencyStreet || "",
            "billing.city": billingDetails?.city || billingDetails?.residencyCity || "",
            "billing.postalCode": billingDetails?.postalCode || billingDetails?.residencyPostalCode || "",
            "billing.iban": billingDetails?.bankIban || "",
            "billing.swift": billingDetails?.bankSwift || "",
            "billing.bankName": billingDetails?.bankName || "",
            "contract.number": contract.contractNumber,
            "contract.date": new Date().toLocaleDateString("sk-SK"),
            "contract.currency": contract.currency || "EUR",
          };

          const outputDir = path.join(process.cwd(), "uploads", "generated-contracts");
          await fs.promises.mkdir(outputDir, { recursive: true });
          
          const result = await generateContractFromTemplate(
            "docx",
            docxPath,
            docxData,
            outputDir,
            contract.id
          );
          
          const relativePdfPath = result.pdfPath.replace(process.cwd() + "/", "");
          const pdfBuffer = await fs.promises.readFile(result.pdfPath);
          const { createHash } = await import("crypto");
          const pdfHash = createHash("sha256").update(pdfBuffer).digest("hex");
          
          await storage.updateContractInstance(contract.id, { 
            pdfPath: relativePdfPath,
            pdfGeneratedAt: new Date(),
            pdfFileSize: pdfBuffer.length,
            pdfFileHash: pdfHash,
            pdfGeneratedBy: req.session.user!.id
          });
          
          await storage.createContractAuditLog({
            contractId: contract.id,
            action: "pdf_generated",
            actorId: req.session.user!.id,
            actorType: "user",
            actorName: req.session.user!.fullName,
            actorEmail: req.session.user!.email,
            ipAddress: req.ip,
            userAgent: req.headers["user-agent"] || null,
            details: JSON.stringify({
              pdfPath: relativePdfPath,
              pdfFileSize: pdfBuffer.length,
              pdfFileHash: pdfHash,
              generatedAt: new Date().toISOString(),
              templateId: categoryDefaultTemplate.id,
              templateSourceDocx: categoryDefaultTemplate.sourceDocxPath
            })
          });
          
          console.log(`[Contract] Auto-generated PDF for ${contract.contractNumber}: ${relativePdfPath} (${pdfBuffer.length} bytes, SHA-256: ${pdfHash.substring(0, 16)}...)`);
          
          // Return updated contract with pdfPath
          const updatedContract = await storage.getContractInstance(contract.id);
          return res.status(201).json(updatedContract);
        }
      } catch (pdfError) {
        console.error(`[Contract] Auto PDF generation failed for ${contract.contractNumber}:`, pdfError);
        // Don't fail the contract creation if PDF generation fails
      }

      res.status(201).json(contract);
    } catch (error) {
      console.error("Error creating contract:", error);
      res.status(500).json({ error: "Failed to create contract" });
    }
  });

  app.patch("/api/contracts/:id", requireAuth, async (req, res) => {
    try {
      const existingContract = await storage.getContractInstance(req.params.id);
      if (!existingContract) {
        return res.status(404).json({ error: "Contract not found" });
      }
      
      const updateData: Record<string, any> = {};
      const allowedFields = [
        "status", "sentContractDate", "signedDate", "pdfPath", 
        "signatureRequestId", "signatureData", "signatureMethod",
        "signedAt", "signedByIp", "currency", "totalAmount",
        "notes", "billingDetailsId", "internalId", "templateId",
        "contractNumber", "customerId", "countryCode"
      ];
      const dateFields = ["sentContractDate", "signedDate", "signedAt"];
      for (const key of allowedFields) {
        if (req.body[key] !== undefined) {
          if (dateFields.includes(key) && typeof req.body[key] === "string") {
            updateData[key] = new Date(req.body[key]);
          } else {
            updateData[key] = req.body[key];
          }
        }
      }
      
      const contract = await storage.updateContractInstance(req.params.id, updateData);

      try {
        const { emitEntityUpdated } = await import("./lib/event-bus");
        const contractCustomer = (contract as any)?.customerId ? await storage.getCustomer((contract as any).customerId) : null;
        await emitEntityUpdated("contract", "contract", contract!.id, existingContract, contract, req.session.user!.id, contractCustomer?.country || null);
      } catch (err) { console.error("[EventBus] contract update emit error:", err); }
      
      try {
        await storage.createContractAuditLog({
          contractId: contract!.id,
          action: "updated",
          actorId: req.session.user!.id,
          actorType: "user",
          actorName: req.session.user!.fullName,
          actorEmail: req.session.user!.email,
          ipAddress: req.ip,
          previousValue: JSON.stringify(existingContract),
          newValue: JSON.stringify(contract)
        });
      } catch (auditError) {
        console.error("Error creating audit log (non-critical):", auditError);
      }
      
      res.json(contract);
    } catch (error) {
      console.error("Error updating contract:", error);
      res.status(500).json({ error: "Failed to update contract" });
    }
  });

  app.delete("/api/contracts/:id", requireAuth, async (req, res) => {
    try {
      const contract = await storage.getContractInstance(req.params.id);
      if (!contract) {
        return res.status(404).json({ error: "Contract not found" });
      }
      
      await storage.deleteContractInstanceProducts(contract.id);
      await storage.deleteContractInstance(req.params.id);
      
      await logActivity(req.session.user!.id, "delete", "contract", contract.id, contract.contractNumber, null, req.ip);
      res.json({ success: true });
    } catch (error) {
      console.error("Error deleting contract:", error);
      res.status(500).json({ error: "Failed to delete contract" });
    }
  });

  app.get("/api/contracts/:id/phone-communications", requireAuth, async (req, res) => {
    try {
      const contract = await storage.getContractInstance(req.params.id);
      if (!contract) return res.status(404).json({ error: "Contract not found" });
      const internalId = contract.internalId;
      if (!internalId) return res.json([]);
      const result = await pool.query(
        `SELECT id, customer_id, user_id, type, direction, content, recipient_phone, status, external_id, provider, contract_id, sent_at, created_at
         FROM communication_messages
         WHERE contract_id = $1 AND provider = 'cbc_legacy'
         ORDER BY sent_at DESC`,
        [internalId]
      );
      res.json(result.rows);
    } catch (error) {
      console.error("Error fetching phone communications:", error);
      res.status(500).json({ error: "Failed to fetch phone communications" });
    }
  });

