  // PATCH /api/v1/collections/:id - Update collection (partial update, all fields optional)
  app.patch("/api/v1/collections/:id", requireApiKey, async (req, res) => {
    try {
      const apiKey = (req as any).apiKey;
      if (!hasPermission(apiKey, "lab_results:write")) {
        return res.status(403).json({
          success: false,
          error: {
            code: "FORBIDDEN",
            message: "API key does not have lab_results:write permission"
          }
        });
      }

      const existing = await storage.getCollection(req.params.id);
      
      if (!existing) {
        return res.status(404).json({
          success: false,
          error: {
            code: "COLLECTION_NOT_FOUND",
            message: "Collection not found"
          }
        });
      }

      // Validate input - all fields are optional
      const parseResult = collectionApiSchema.partial().safeParse(req.body);
      if (!parseResult.success) {
        const errors = parseResult.error.errors.map(e => ({
          field: e.path.join("."),
          message: e.message
        }));
        return res.status(400).json({
          success: false,
          error: {
            code: "VALIDATION_ERROR",
            message: "Validation failed",
            details: errors
          }
        });
      }

      const { collectionId, externalCollectionRef, ...updateData } = parseResult.data;
      const parsedData = filterCollectionFields(parseCollectionDates(updateData));

      const result = await storage.updateCollection(req.params.id, parsedData);

      res.json({
        success: true,
        data: {
          id: result?.id,
          cbu: (result as any)?.cbuNumber || null,
          updatedAt: result?.updatedAt
        },
        message: "Collection updated"
      });

    } catch (error) {
      console.error("Error updating collection:", error);
      res.status(500).json({
        success: false,
        error: {
          code: "INTERNAL_ERROR",
          message: "Failed to update collection"
        }
      });
    }
  });

  // PATCH /api/v1/collections - Update collection by body (cbuNumber or deliveryId)
  app.patch("/api/v1/collections", requireApiKey, async (req, res) => {
    try {
      const apiKey = (req as any).apiKey;
      if (!hasPermission(apiKey, "lab_results:write")) {
        return res.status(403).json({
          success: false,
          error: {
            code: "FORBIDDEN",
            message: "API key does not have lab_results:write permission"
          }
        });
      }

      const { cbuNumber, deliveryId, collectionId: bodyCollectionId, ...bodyData } = req.body;

      let existing: any = null;
      if (bodyCollectionId) {
        existing = await storage.getCollection(bodyCollectionId);
      }
      if (!existing && deliveryId) {
        existing = await storage.getCollection(deliveryId);
        if (!existing) existing = await storage.getCollectionByLegacyId(String(deliveryId));
      }
      if (!existing && cbuNumber) {
        existing = await storage.getCollectionByCbuNumber(cbuNumber);
      }

      if (!existing) {
        return res.status(404).json({
          success: false,
          error: {
            code: "COLLECTION_NOT_FOUND",
            message: "Collection not found by cbuNumber, deliveryId, or collectionId"
          }
        });
      }

      const parseResult = collectionApiSchema.partial().safeParse(bodyData);
      if (!parseResult.success) {
        const errors = parseResult.error.errors.map((e: any) => ({
          field: e.path.join("."),
          message: e.message
        }));
        return res.status(422).json({
          success: false,
          error: {
            code: "VALIDATION_ERROR",
            message: "Validation failed",
            details: errors
          }
        });
      }

      const { collectionId: _cid, externalCollectionRef: _ecr, ...updateFields } = parseResult.data;
      const parsedData = filterCollectionFields(parseCollectionDates(updateFields));

      const result = await storage.updateCollection(existing.id, parsedData);

      res.json({
        success: true,
        data: {
          id: result?.id,
          cbu: (result as any)?.cbuNumber || existing.cbuNumber || null,
          updatedAt: result?.updatedAt
        },
        message: "Collection updated"
      });

    } catch (error) {
      console.error("Error updating collection by body:", error);
      res.status(500).json({
        success: false,
        error: {
          code: "INTERNAL_ERROR",
          message: "Failed to update collection"
        }
      });
    }
  });

  // POST /api/v1/collections - Create new collection
  app.post("/api/v1/collections", requireApiKey, async (req, res) => {
    try {
      const apiKey = (req as any).apiKey;
      if (!hasPermission(apiKey, "lab_results:write")) {
        return res.status(403).json({
          success: false,
          error: {
            code: "FORBIDDEN",
            message: "API key does not have lab_results:write permission"
          }
        });
      }

      const parseResult = collectionApiSchema.safeParse(req.body);
      if (!parseResult.success) {
        const errors = parseResult.error.errors.map(e => ({
          field: e.path.join("."),
          message: e.message
        }));
        return res.status(422).json({
          success: false,
          error: {
            code: "VALIDATION_ERROR",
            message: "Validation failed",
            details: errors
          }
        });
      }

      const { collectionId, externalCollectionRef, cbuNumber, ...createData } = parseResult.data;

      if (cbuNumber) {
        const existingByCbu = await storage.getCollectionByCbuNumber(cbuNumber);
        if (existingByCbu) {
          const parsedData = filterCollectionFields(parseCollectionDates(createData));
          const result = await storage.updateCollection(existingByCbu.id, parsedData);
          return res.json({
            success: true,
            data: {
              id: result?.id || existingByCbu.id,
              cbu: cbuNumber,
            },
            message: "Collection updated (existing CBU)"
          });
        }
      }

      if (!createData.countryCode && !((parseResult.data as any).countryCode)) {
        return res.status(422).json({
          success: false,
          error: {
            code: "VALIDATION_ERROR",
            message: "countryCode is required for creating a new collection"
          }
        });
      }

      const parsedData = filterCollectionFields(parseCollectionDates({ ...createData, cbuNumber }));

      const result = await storage.createCollection(parsedData as any);

      res.status(201).json({
        success: true,
        data: {
          id: result.id,
          cbu: result.cbuNumber || cbuNumber || null,
          createdAt: result.createdAt
        },
        message: "Collection created"
      });

    } catch (error) {
      console.error("Error creating collection:", error);
      res.status(500).json({
        success: false,
        error: {
          code: "INTERNAL_ERROR",
          message: "Failed to create collection"
        }
      });
    }
  });

  // ========================================
  // API Key Management (Admin only)
  // ========================================

  // Helper: Check if user has admin role (supports both legacy role field and roleId-based permissions)
  const requireAdmin = async (req: Request, res: Response, next: NextFunction) => {
    const user = (req as any).user;
    if (!user) {
      return res.status(403).json({ error: "Admin access required" });
    }
    
    // Check legacy role field first
    if (user.role === "admin") {
      return next();
    }
    
    // Check role-based permissions via roleId if available
    if (user.roleId) {
      try {
        const role = await storage.getRole(user.roleId);
        if (role && role.name === "Admin") {
          return next();
        }
      } catch (e) {
        console.error("Error checking role permissions:", e);
      }
    }
    
    return res.status(403).json({ error: "Admin access required" });
  };

  // Helper: Check if user has admin or manager role
  const requireAdminOrManager = async (req: Request, res: Response, next: NextFunction) => {
    // Try session user first, then any attached user
    const user = req.session?.user || (req as any).user;
    
    if (!user) {
      return res.status(403).json({ error: "Admin or Manager access required" });
    }
    
    // Check legacy role field first
    if (user.role === "admin" || user.role === "manager") {
      return next();
    }
    
    // Check role-based permissions via roleId if available
    if (user.roleId) {
      try {
        const role = await storage.getRole(user.roleId);
        if (role && (role.name === "Admin" || role.name === "Manager")) {
          return next();
        }
      } catch (e) {
        console.error("Error checking role permissions:", e);
      }
    }
    
    return res.status(403).json({ error: "Admin or Manager access required" });
  };

  // GET /api/api-keys - List all API keys
  app.get("/api/api-keys", requireAuth, requireAdminOrManager, async (req, res) => {
    try {
      const keys = await storage.getAllApiKeys();
      // Don't expose the hash, only prefix and metadata
      const safeKeys = keys.map(k => ({
        id: k.id,
        name: k.name,
        keyPrefix: k.keyPrefix + "...",
        permissions: k.permissions,
        rateLimit: k.rateLimit,
        isActive: k.isActive,
        lastUsedAt: k.lastUsedAt,
        expiresAt: k.expiresAt,
        createdAt: k.createdAt
      }));
      res.json(safeKeys);
    } catch (error) {
      console.error("Error fetching API keys:", error);
      res.status(500).json({ error: "Failed to fetch API keys" });
    }
  });

  // POST /api/api-keys - Create new API key
  app.post("/api/api-keys", requireAuth, requireAdminOrManager, async (req, res) => {
    try {
      const { name, permissions, rateLimit, expiresAt } = req.body;

      if (!name) {
        return res.status(400).json({ error: "Name is required" });
      }

      // Generate a new API key
      const crypto = await import("crypto");
      const apiKey = `idx_${crypto.randomBytes(32).toString("hex")}`;
      const keyPrefix = apiKey.substring(0, 8);
      const keyHash = crypto.createHash("sha256").update(apiKey).digest("hex");

      const keyRecord = await storage.createApiKey({
        name,
        keyHash,
        keyPrefix,
        rawKey: apiKey,
        permissions: permissions || ["lab_results:write"],
        rateLimit: rateLimit || 60,
        isActive: true,
        expiresAt: expiresAt ? new Date(expiresAt) : null,
        createdBy: req.session?.user?.id || (req as any).user?.id
      });

      // Return the key only once - it cannot be retrieved later
      res.status(201).json({
        id: keyRecord.id,
        name: keyRecord.name,
        apiKey, // Only returned once!
        keyPrefix: keyRecord.keyPrefix,
        permissions: keyRecord.permissions,
        rateLimit: keyRecord.rateLimit,
        expiresAt: keyRecord.expiresAt,
        createdAt: keyRecord.createdAt,
        message: "Save this API key securely - it will not be shown again"
      });

    } catch (error) {
      console.error("Error creating API key:", error);
      res.status(500).json({ error: "Failed to create API key" });
    }
  });

