  app.post("/api/message-templates/:id/copy-translate", requireAuth, async (req, res) => {
    try {
      const { targetLanguage, translate } = req.body;
      if (!targetLanguage) return res.status(400).json({ error: "targetLanguage required" });
      
      const source = await storage.getMessageTemplate(req.params.id);
      if (!source) return res.status(404).json({ error: "Template not found" });

      const LANG_NAMES: Record<string, string> = {
        sk: "Slovak", cs: "Czech", en: "English", hu: "Hungarian",
        ro: "Romanian", it: "Italian", de: "German"
      };
      const sourceLangName = LANG_NAMES[source.language] || source.language;
      const targetLangName = LANG_NAMES[targetLanguage] || targetLanguage;

      let name = source.name;
      let subject = source.subject || "";
      let content = source.content || "";
      let contentHtml = source.contentHtml || "";

      if (translate) {
        const openaiInstance = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
        const prompt = `Translate the following from ${sourceLangName} to ${targetLangName}. Keep all {{variables}} exactly as they are. Keep HTML tags exactly as they are. Return ONLY the translated text, nothing else.`;

        const translateText = async (text: string, isHtml: boolean): Promise<string> => {
          if (!text || text.trim().length === 0) return text;
          const completion = await openaiInstance.chat.completions.create({
            model: "gpt-4o-mini",
            messages: [
              { role: "system", content: prompt + (isHtml ? " The text contains HTML markup - preserve all HTML tags exactly." : "") },
              { role: "user", content: text }
            ],
            temperature: 0.3,
          });
          return completion.choices[0]?.message?.content || text;
        };

        const [translatedName, translatedSubject, translatedContent, translatedContentHtml] = await Promise.all([
          translateText(name, false),
          subject ? translateText(subject, false) : Promise.resolve(""),
          translateText(content, false),
          contentHtml ? translateText(contentHtml, true) : Promise.resolve(""),
        ]);

        name = translatedName;
        subject = translatedSubject;
        content = translatedContent;
        contentHtml = translatedContentHtml;
      }

      const newTemplate = await storage.createMessageTemplate({
        name: name,
        description: source.description,
        type: source.type,
        format: source.format,
        subject: subject || undefined,
        content: content,
        contentHtml: contentHtml || undefined,
        categoryId: source.categoryId || undefined,
        language: targetLanguage,
        tags: source.tags || [],
        isDefault: false,
        isActive: source.isActive,
        createdBy: req.session.user?.id,
      });

      res.status(201).json(newTemplate);
    } catch (error) {
      console.error("Error copying/translating template:", error);
      res.status(500).json({ error: "Failed to copy template" });
    }
  });



  const uploadMsgZip = multer({ storage: multer.diskStorage({ destination: (_req, _file, cb) => { const dir = path.join(process.cwd(), "uploads", "temp"); if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true }); cb(null, dir); }, filename: (_req, _file, cb) => cb(null, `msg-zip-${Date.now()}.zip`) }), limits: { fileSize: 250 * 1024 * 1024 }, fileFilter: (_req, file, cb) => { if (file.mimetype === "application/zip" || file.mimetype === "application/x-zip-compressed" || file.originalname.endsWith(".zip")) cb(null, true); else cb(new Error("Only ZIP files allowed")); } });

  app.post("/api/message-templates/import-zip", requireAuth, requireAdminOrManager, (req, res, next) => { req.setTimeout(600000); res.setTimeout(600000); next(); }, uploadMsgZip.single("file"), async (req, res) => {
    const zipPath = (req as any).file?.path;
    try {
      const categoryId = req.body.categoryId || null;
      const language = req.body.language || "sk";
      if (!zipPath) return res.status(400).json({ error: "No file uploaded" });

      const _rq: any = (typeof require === "function") ? require : eval("require");
      const _azm = _rq("adm" + "-zip");
      const AdmZip = _azm.default || _azm;
      const _mrm = _rq("msg" + "reader");
      const MsgReader = _mrm.default || _mrm;
      let decompressRTF: ((buf: Buffer) => Buffer) | null = null;
      let deEncapsulateSync: ((rtf: string) => { mode: string; text?: string; html?: string }) | null = null;
      try { decompressRTF = _rq("@kenjiuno/decompressrtf").decompressRTF; } catch {}
      try { deEncapsulateSync = _rq("rtf-stream-parser").deEncapsulateSync; } catch {}

      const FULL_NAME_VAR = "{{customer.firstName}} {{customer.lastName}}";
      const SALUTATION_RX: [RegExp, string][] = [
        [/Vážen[áý]\s+pan[ie]?\s+/i, `$&${FULL_NAME_VAR}, `],
        [/Vážen[áý]\s+/i, `$&${FULL_NAME_VAR}, `],
        [/Dobrý deň,?\s*/i, `$&${FULL_NAME_VAR}, `],
        [/Dobrý den,?\s*/i, `$&${FULL_NAME_VAR}, `],
        [/Ahoj,?\s*/i, `$&${FULL_NAME_VAR}, `],
        [/Dear\s+/i, `$&${FULL_NAME_VAR}, `],
        [/Sehr geehrte[r]?\s+/i, `$&${FULL_NAME_VAR}, `],
        [/Gentile\s+/i, `$&${FULL_NAME_VAR}, `],
        [/Tisztelt\s+/i, `$&${FULL_NAME_VAR}, `],
        [/Stimate?\s+/i, `$&${FULL_NAME_VAR}, `],
      ];
      const VAR_PATTERNS: [RegExp, string][] = [
        [/\b(?:meno a priezvisko|jméno a příjmení|full.?name|celé jméno|celé meno)\b/i, FULL_NAME_VAR],
        [/\b(?:meno|jméno|name|ime|nome|név|nume|vorname|first.?name|krstné meno|křestní jméno)\b/i, "{{customer.firstName}}"],
        [/\b(?:priezvisko|příjmení|surname|last.?name|nachname|cognome|vezetéknév|numele de familie)\b/i, "{{customer.lastName}}"],
        [/\b(?:rodné číslo|birth.?number|születési szám|cod numeric personal)\b/i, "{{customer.birthNumber}}"],
        [/\b(?:číslo zmluvy|číslo smlouvy|contract.?number|vertragsnummer|numero contratto|szerződésszám|număr contract)\b/i, "{{contract.contractNumber}}"],
        [/\b(?:dátum narodenia|datum narození|date.?of.?birth|születési dátum|data nașterii|geburtsdatum)\b/i, "{{customer.dateOfBirth}}"],
        [/\b(?:telefón|telefon|phone|telefono|tel\.?č|číslo telefónu)\b/i, "{{customer.phone}}"],
        [/\b(?:e[\-‑]?mail(?:ov[áa])?(?:\s+adresa)?)\b/i, "{{customer.email}}"],
        [/\b(?:adresa|address|indirizzo|cím|adresă|adresse|bydlisko|bydliště)\b/i, "{{customer.address}}"],
        [/\b(?:ičo|ič|ico|id.?number|identifikačné číslo)\b/i, "{{company.companyId}}"],
        [/\b(?:dátum registrácie|datum registrace|registration.?date)\b/i, "{{contract.registrationDate}}"],
      ];

      const MIME_MAP: Record<string, string> = {
        ".pdf": "application/pdf", ".png": "image/png", ".jpg": "image/jpeg", ".jpeg": "image/jpeg",
        ".gif": "image/gif", ".doc": "application/msword",
        ".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        ".xls": "application/vnd.ms-excel",
        ".xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      };

      function toStr(raw: any): string {
        if (!raw) return "";
        if (typeof raw === "string") return raw.replace(/\x00/g, "");
        let buf: Buffer;
        if (raw instanceof Uint8Array || raw instanceof Buffer) { buf = Buffer.from(raw); }
        else if (raw instanceof ArrayBuffer) { buf = Buffer.from(raw); }
        else { return String(raw).replace(/\x00/g, ""); }
        if (buf.length >= 2) {
          if (buf[0] === 0xFF && buf[1] === 0xFE) return buf.toString("utf16le").replace(/\x00/g, "");
          if (buf[0] === 0xFE && buf[1] === 0xFF) {
            const swapped = Buffer.alloc(buf.length);
            for (let i = 0; i < buf.length - 1; i += 2) { swapped[i] = buf[i + 1]; swapped[i + 1] = buf[i]; }
            return swapped.toString("utf16le").replace(/\x00/g, "");
          }
          let nullCount = 0;
          const check = Math.min(buf.length, 200);
          for (let i = 0; i < check; i++) { if (buf[i] === 0) nullCount++; }
          if (nullCount > check * 0.2) return buf.toString("utf16le").replace(/\x00/g, "");
        }
        return buf.toString("utf-8").replace(/\x00/g, "");
      }

      function isReadableText(s: string): boolean {
        if (!s || s.length < 3) return false;
        let printable = 0;
        const len = Math.min(s.length, 500);
        for (let i = 0; i < len; i++) {
          const c = s.charCodeAt(i);
          if ((c >= 0x20 && c <= 0x7E) || (c >= 0xA0 && c <= 0x024F) || c === 0x0A || c === 0x0D || c === 0x09) printable++;
        }
        return (printable / len) > 0.7;
      }

      function tryDecompressRtf(rawBuf: Buffer): string {
        if (!decompressRTF) return "";
        try {
          const rtfBuf = decompressRTF(rawBuf);
          const rtfStr = rtfBuf.toString("utf-8");
          if (deEncapsulateSync) {
            try {
              const result = deEncapsulateSync(rtfStr);
              if (result.html && isReadableText(result.html.replace(/<[^>]*>/g, ""))) return result.html;
              if (result.text && isReadableText(result.text)) return result.text.split("\n").map((l: string) => `<p>${l.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}</p>`).join("\n");
            } catch {}
          }
          const hexDecoded = rtfStr.replace(/\\'([0-9a-f]{2})/gi, (_: string, hex: string) => String.fromCharCode(parseInt(hex, 16)));
          let text = hexDecoded.replace(/\\par\b/g, "\n").replace(/\{\\[^{}]*\}/g, "").replace(/\\\w+\s?/g, "").replace(/[{}]/g, "").trim();
          if (isReadableText(text)) return text.split("\n").map((l: string) => `<p>${l.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}</p>`).join("\n");
        } catch {}
        return "";
      }

      function cleanHtml(raw: any): string {
        let html = toStr(raw);
        html = html.replace(/<!--\[if.*?\]>.*?<!\[endif\]-->/gs, "");
        html = html.replace(/<!--.*?-->/gs, "");
        html = html.replace(/<xml[^>]*>.*?<\/xml>/gis, "");
        html = html.replace(/<o:p>\s*<\/o:p>/gi, "");
        html = html.replace(/<o:p>(.*?)<\/o:p>/gi, "$1");
        html = html.replace(/<\/?o:[^>]+>/g, "");
        html = html.replace(/<\/?v:[^>]+>/g, "");
        html = html.replace(/<\/?w:[^>]+>/g, "");
        html = html.replace(/\s*xmlns:[a-z]+="[^"]*"/g, "");
        const bodyMatch = html.match(/<body[^>]*>(.*?)<\/body>/is);
        if (bodyMatch) html = bodyMatch[1];
        html = html.replace(/\s*class="Mso[^"]*"/g, "");
        html = html.replace(/\s*style="([^"]*)"/g, (_m: string, s: string) => {
          if (typeof s !== "string") return _m;
          const kept = s.split(";").filter((p: string) => p.trim() && !/^mso-/i.test(p.trim()) && !/^tab-stops/i.test(p.trim())).join("; ").trim();
          return kept ? ` style="${kept}"` : "";
        });
        html = html.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, (styleBlock: string) => {
          const cleaned = styleBlock.replace(/mso-[^;:]+:[^;]+;?/gi, "").replace(/tab-stops[^;]+;?/gi, "");
          if (cleaned.replace(/<\/?style[^>]*>/gi, "").trim().length < 10) return "";
          return cleaned;
        });
        html = html.replace(/\n\s*\n\s*\n/g, "\n\n");
        return html.trim();
      }

      function extractNumberPrefix(filename: string): [string | null, string] {
        const base = path.basename(filename, path.extname(filename));
        let m = base.match(/^template[_\s]*(\d+)[_\s]*[-_]\s*(.*)/i);
        if (m) return [m[1], m[2].trim().replace(/^[-_ ]+|[-_ ]+$/g, "")];
        m = base.match(/^(\d+)[_\s.\-]+(.+)/);
        if (m) return [m[1], m[2].trim().replace(/^[-_ ]+|[-_ ]+$/g, "")];
        return [null, base];
      }

      function detectVars(text: string): string[] {
        const found = new Set<string>();
        for (const [rx, v] of VAR_PATTERNS) { if (rx.test(text)) found.add(v); }
        return Array.from(found);
      }

      function insertSalutation(html: string): string {
        for (const [rx, repl] of SALUTATION_RX) {
          if (rx.test(html)) { html = html.replace(rx, repl); break; }
        }
        return html;
      }

      const zip = new AdmZip(zipPath);
      const entries = zip.getEntries().filter((e: any) => !e.isDirectory && e.entryName.toLowerCase().endsWith(".msg") && !e.entryName.startsWith("__MACOSX"));
      const total = entries.length;

      const created: any[] = [];
      const errors: any[] = [];
      const attachmentDir = path.join(process.cwd(), "uploads", "template-attachments");
      if (!fs.existsSync(attachmentDir)) fs.mkdirSync(attachmentDir, { recursive: true });

      for (const entry of entries) {
        try {
          const msgBuf = entry.getData();
          const reader = new MsgReader(msgBuf);
          const fileData = reader.getFileData();

          const subject = toStr(fileData.subject);
          let htmlBody = "";
          let plainBody = "";

          // 1) Try bodyHtml (MAPI 0x1013) — prefer HTML with full formatting
          if (fileData.bodyHtml) {
            const rawHtml = toStr(fileData.bodyHtml);
            if (rawHtml && rawHtml.length > 10) htmlBody = cleanHtml(rawHtml);
          }

          // 2) Try plain text body (MAPI 0x1000) — original msgreader behavior
          const rawBody = fileData.body;
          if (typeof rawBody === "string" && rawBody.length > 0) {
            plainBody = rawBody;
          } else if (rawBody && typeof rawBody !== "string") {
            const decoded = toStr(rawBody);
            if (isReadableText(decoded)) plainBody = decoded;
          }

          // 3) If no HTML yet, try compressed RTF (MAPI 0x1009)
          if (!htmlBody && fileData.compressedRtf) {
            const rtfRaw = fileData.compressedRtf;
            const rtfBuf = (rtfRaw instanceof Uint8Array || rtfRaw instanceof Buffer) ? Buffer.from(rtfRaw) : (rtfRaw instanceof ArrayBuffer ? Buffer.from(rtfRaw) : null);
            if (rtfBuf) {
              const fromRtf = tryDecompressRtf(rtfBuf);
              if (fromRtf) htmlBody = cleanHtml(fromRtf);
            }
          }

          // 4) Convert plain text to HTML if no HTML found
          if (!htmlBody && plainBody) {
            htmlBody = plainBody.split("\n").map((line: string) => {
              const escaped = line.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
              return escaped.trim() ? `<p>${escaped}</p>` : "<p>&nbsp;</p>";
            }).join("\n");
          }

          htmlBody = insertSalutation(htmlBody);

          const detectedVars = detectVars(plainBody || htmlBody);
          if (htmlBody.includes("{{customer.firstName}}") && !detectedVars.includes("{{customer.firstName}}")) detectedVars.push("{{customer.firstName}}");
          if (htmlBody.includes("{{customer.lastName}}") && !detectedVars.includes("{{customer.lastName}}")) detectedVars.push("{{customer.lastName}}");

          const savedAttachments: { fileName: string; filePath: string; mimeType: string; size: number }[] = [];
          const attCount = fileData.attachments?.length || 0;
          for (let ai = 0; ai < attCount; ai++) {
            try {
              const att = reader.getAttachment(ai);
              if (!att) continue;
              const attName = att.fileName || fileData.attachments[ai]?.name || `attachment_${ai}`;
              const contentId = (fileData.attachments[ai] as any)?.pidContentId || (fileData.attachments[ai] as any)?.contentId || null;
              const isInline = !!contentId;
              const ext = path.extname(attName).toLowerCase();
              const mimeType = MIME_MAP[ext] || "application/octet-stream";

              if (isInline && [".png", ".jpg", ".jpeg", ".gif", ".bmp", ".tiff", ".tif", ".webp"].includes(ext) && att.content) {
                const dataUri = `data:${mimeType};base64,${Buffer.from(att.content).toString("base64")}`;
                if (contentId) htmlBody = htmlBody.replace(new RegExp(`cid:${contentId.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}`, "g"), dataUri);
              } else if (att.content && att.content.length > 0) {
                const safeFileName = `${Date.now()}-${Math.random().toString(36).slice(2,8)}-${attName.replace(/[^a-zA-Z0-9._-]/g, "_")}`;
                const diskPath = path.join(attachmentDir, safeFileName);
                fs.writeFileSync(diskPath, Buffer.from(att.content));
                savedAttachments.push({ fileName: attName, filePath: `uploads/template-attachments/${safeFileName}`, mimeType, size: att.content.length });
              }
            } catch {}
          }

          const [numPrefix, namePart] = extractNumberPrefix(entry.entryName);
          let templateName: string;
          if (subject) {
            templateName = numPrefix ? `${numPrefix} - ${subject}` : subject;
          } else {
            templateName = numPrefix ? `${numPrefix} - ${namePart}` : namePart;
          }
          if (!templateName.trim()) templateName = path.basename(entry.entryName, ".msg");

          const newTemplate = await storage.createMessageTemplate({
            name: templateName,
            description: subject && subject !== templateName ? subject : null,
            type: "email",
            format: htmlBody ? "html" : "text",
            subject: subject || templateName,
            content: plainBody || "",
            contentHtml: htmlBody || null,
            categoryId: categoryId,
            language: language,
            tags: detectedVars,
            isDefault: false,
            isActive: true,
            createdBy: req.session.user?.id,
            attachments: savedAttachments.length > 0 ? savedAttachments : null,
          });
          created.push({ id: newTemplate.id, name: templateName, fileName: entry.entryName, attachmentCount: savedAttachments.length, detectedVariables: detectedVars });
        } catch (err: any) {
          errors.push({ fileName: entry.entryName, error: err.message });
        }
      }

      res.json({ total, created: created.length, errors: errors.length, templates: created, errorDetails: errors });
    } catch (error: any) {
      console.error("Error importing MSG ZIP:", error);
      res.status(500).json({ error: error.message || "Failed to import templates" });
    } finally {
      if (zipPath) try { fs.unlinkSync(zipPath); } catch {}
    }
  });


  app.get("/api/message-templates/:id/attachments", requireAuth, async (req, res) => {
    try {
      const template = await storage.getMessageTemplate(req.params.id);
      if (!template) return res.status(404).json({ error: "Template not found" });
      const attachments = (template as any).attachments || [];
      const allowedBase = path.resolve(process.cwd(), "uploads", "template-attachments");
      const result = attachments.map((att: any) => {
        try {
          const absPath = path.resolve(process.cwd(), att.filePath.replace(/^\//, ""));
          if (!absPath.startsWith(allowedBase)) return { fileName: att.fileName, error: "Invalid path" };
          if (!fs.existsSync(absPath)) return { fileName: att.fileName, mimeType: att.mimeType, size: att.size, error: "File not found" };
          const data = fs.readFileSync(absPath);
          return { fileName: att.fileName, mimeType: att.mimeType, size: att.size, contentBase64: data.toString("base64") };
        } catch { return { fileName: att.fileName, error: "Read error" }; }
      });
      res.json(result);
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

  const templateAttachmentStorage = multer.diskStorage({
    destination: (req, file, cb) => {
      const dir = path.join(process.cwd(), "uploads", "template-attachments");
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
      cb(null, dir);
    },
    filename: (req, file, cb) => {
      const uniqueSuffix = Date.now() + "-" + Math.round(Math.random() * 1e9);
      const ext = path.extname(file.originalname);
      const safeName = file.originalname.replace(/[^a-zA-Z0-9._-]/g, "_").replace(ext, "");
      cb(null, `${safeName}-${uniqueSuffix}${ext}`);
    },
  });
  const uploadTemplateAttachment = multer({
    storage: templateAttachmentStorage,
    limits: { fileSize: 15 * 1024 * 1024 },
  });

  app.post("/api/message-templates/:id/attachments", requireAuth, uploadTemplateAttachment.array("files", 10), async (req, res) => {
    try {
      const template = await storage.getMessageTemplate(req.params.id);
      if (!template) return res.status(404).json({ error: "Template not found" });
      const existing: any[] = (template as any).attachments || [];
      const uploaded = (req.files as Express.Multer.File[]) || [];
      const newAttachments = uploaded.map(f => ({
        fileName: f.originalname,
        filePath: `uploads/template-attachments/${f.filename}`,
        mimeType: f.mimetype,
        size: f.size,
      }));
      const merged = [...existing, ...newAttachments];
      await storage.updateMessageTemplate(req.params.id, { attachments: merged } as any);
      res.json({ success: true, attachments: merged });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

  app.delete("/api/message-templates/:id/attachments/:idx", requireAuth, async (req, res) => {
    try {
      const template = await storage.getMessageTemplate(req.params.id);
      if (!template) return res.status(404).json({ error: "Template not found" });
      const existing: any[] = (template as any).attachments || [];
      const idx = parseInt(req.params.idx);
      if (isNaN(idx) || idx < 0 || idx >= existing.length) return res.status(400).json({ error: "Invalid index" });
      const removed = existing[idx];
      try {
        const absPath = path.resolve(process.cwd(), removed.filePath.replace(/^\//, ""));
        const allowedBase = path.resolve(process.cwd(), "uploads", "template-attachments");
        if (absPath.startsWith(allowedBase) && fs.existsSync(absPath)) fs.unlinkSync(absPath);
      } catch {}
      const updated = existing.filter((_, i) => i !== idx);
      await storage.updateMessageTemplate(req.params.id, { attachments: updated } as any);
      res.json({ success: true, attachments: updated });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

