  app.get("/api/agent-sessions/shift-data", requireAuth, async (req, res) => {
    try {
      const userId = req.session.user!.id;
      const todayStart = startOfDay(new Date());
      const todayEnd = endOfDay(new Date());

      const sessions = await db.select({
        contactsHandled: agentSessions.contactsHandled,
        totalBreakTime: agentSessions.totalBreakTime,
        totalCallTime: agentSessions.totalCallTime,
        totalWorkTime: agentSessions.totalWorkTime,
        campaignId: agentSessions.campaignId,
      }).from(agentSessions)
        .where(and(
          eq(agentSessions.userId, userId),
          gte(agentSessions.startedAt, todayStart),
          lte(agentSessions.startedAt, todayEnd)
        ));

      const totals = sessions.reduce((acc, s) => ({
        contactsHandled: acc.contactsHandled + (s.contactsHandled || 0),
        totalBreakSeconds: acc.totalBreakSeconds + (s.totalBreakTime || 0),
        totalCallSeconds: acc.totalCallSeconds + (s.totalCallTime || 0),
        totalWorkSeconds: acc.totalWorkSeconds + (s.totalWorkTime || 0),
      }), { contactsHandled: 0, totalBreakSeconds: 0, totalCallSeconds: 0, totalWorkSeconds: 0 });

      let callerIdNumber: string | null = null;
      const sipExt = await db.select({
        assignedToCollaboratorId: sipExtensions.assignedToCollaboratorId,
      }).from(sipExtensions)
        .where(eq(sipExtensions.assignedToUserId, userId))
        .limit(1);

      if (sipExt.length > 0 && sipExt[0].assignedToCollaboratorId) {
        const collab = await db.select({ outboundCallerId: collaborators.outboundCallerId })
          .from(collaborators)
          .where(eq(collaborators.id, sipExt[0].assignedToCollaboratorId))
          .limit(1);
        if (collab.length > 0) callerIdNumber = collab[0].outboundCallerId;
      }

      const campaignIdsParam = (req.query.campaignIds as string) || "";
      const campaignIds = campaignIdsParam.split(",").filter(Boolean);

      const campaignData: Record<string, {
        workingHoursStart: string; workingHoursEnd: string;
        dailyCallQuota: number | null; contactsToday: number;
        maxContactsPerDay: number | null; conversionGoal: number;
      }> = {};

      if (campaignIds.length > 0) {
        const [schedules, opSettings, campRows] = await Promise.all([
          db.select().from(campaignSchedules).where(inArray(campaignSchedules.campaignId, campaignIds)),
          db.select().from(campaignOperatorSettings).where(and(
            inArray(campaignOperatorSettings.campaignId, campaignIds),
            eq(campaignOperatorSettings.userId, userId)
          )),
          db.select({ id: campaigns.id, conversionGoal: campaigns.conversionGoal, settings: campaigns.settings })
            .from(campaigns).where(inArray(campaigns.id, campaignIds)),
        ]);
        const scheduleMap = new Map(schedules.map(s => [s.campaignId, s]));
        const opMap = new Map(opSettings.map(s => [s.campaignId, s]));
        const campMap = new Map(campRows.map(c => [c.id, c]));
        const todayDOW = new Date().getDay(); // 0=Sun,1=Mon,...,6=Sat

        for (const cId of campaignIds) {
          const sched = scheduleMap.get(cId);
          const op = opMap.get(cId);
          const camp = campMap.get(cId);
          const contactsToday = sessions.filter(s => s.campaignId === cId).reduce((a, s) => a + (s.contactsHandled || 0), 0);

          // Default to campaignSchedules single-value fallback
          let wStart = sched?.workingHoursStart || "09:00";
          let wEnd = sched?.workingHoursEnd || "17:00";
          // Override with per-day weeklySchedule from campaigns.settings if available
          if (camp?.settings) {
            try {
              const parsed = JSON.parse(camp.settings);
              const daySchedule = parsed.weeklySchedule?.[todayDOW];
              if (daySchedule?.enabled && Array.isArray(daySchedule.slots) && daySchedule.slots.length > 0) {
                wStart = daySchedule.slots[0].startTime || wStart;
                wEnd = daySchedule.slots[daySchedule.slots.length - 1].endTime || wEnd;
              }
            } catch {}
          }

          campaignData[cId] = {
            workingHoursStart: wStart,
            workingHoursEnd: wEnd,
            dailyCallQuota: op?.dailyCallQuota ?? null,
            contactsToday,
            maxContactsPerDay: op?.maxContactsPerDay ?? null,
            conversionGoal: parseFloat(camp?.conversionGoal || "0"),
          };
        }
      }

      // Fetch conversion disposition codes, all call logs today and answered call logs in parallel
      const conversionCodesRows = await db.select({ code: campaignDispositions.code })
        .from(campaignDispositions)
        .where(eq(campaignDispositions.isConversion, true));
      const conversionCodes = [...new Set(conversionCodesRows.map(d => d.code))];

      const [dispositionsRows, todayCallLogs, totalCallsRows, conversionsRows] = await Promise.all([
        db.select({ count: count() })
          .from(campaignContactHistory)
          .where(and(
            eq(campaignContactHistory.userId, userId),
            gte(campaignContactHistory.createdAt, todayStart),
            lte(campaignContactHistory.createdAt, todayEnd)
          )),
        db.select({
          durationSeconds: callLogs.durationSeconds,
          status: callLogs.status,
          campaignId: callLogs.campaignId,
        }).from(callLogs)
          .where(and(
            eq(callLogs.userId, userId),
            gte(callLogs.startedAt, todayStart),
            lte(callLogs.startedAt, todayEnd),
            inArray(callLogs.status, ['answered', 'completed'])
          )),
        db.select({ count: count() }).from(callLogs)
          .where(and(
            eq(callLogs.userId, userId),
            gte(callLogs.startedAt, todayStart),
            lte(callLogs.startedAt, todayEnd)
          )),
        conversionCodes.length > 0
          ? db.select({ count: count() }).from(campaignContactHistory)
            .where(and(
              eq(campaignContactHistory.userId, userId),
              gte(campaignContactHistory.createdAt, todayStart),
              lte(campaignContactHistory.createdAt, todayEnd),
              inArray(campaignContactHistory.newStatus, conversionCodes)
            ))
          : Promise.resolve([{ count: 0 }]),
      ]);

      const callsCount = todayCallLogs.length;
      const callSecondsFromLogs = todayCallLogs.reduce((a, c) => a + (c.durationSeconds || 0), 0);

      // Use the higher of: agentSessions.contactsHandled OR actual callLogs count
      const effectiveContactsHandled = Math.max(totals.contactsHandled, callsCount);
      const effectiveCallSeconds = Math.max(totals.totalCallSeconds, callSecondsFromLogs);

      res.json({
        callerIdNumber,
        contactsHandled: effectiveContactsHandled,
        totalCallsToday: Number(totalCallsRows[0]?.count || 0),
        conversionsToday: Number(conversionsRows[0]?.count || 0),
        totalBreakMinutes: Math.floor(totals.totalBreakSeconds / 60),
        totalBreakSeconds: totals.totalBreakSeconds,
        totalCallMinutes: Math.floor(effectiveCallSeconds / 60),
        totalWorkMinutes: Math.floor(totals.totalWorkSeconds / 60),
        dispositionsToday: Number(dispositionsRows[0]?.count || 0),
        campaignData,
      });
    } catch (error) {
      console.error("Error fetching shift data:", error);
      res.status(500).json({ error: "Failed to fetch shift data" });
    }
  });

