  app.post("/api/status-definitions/seed", requireAuth, async (req, res) => {
    try {
      if (!requireAdminForStatus(req, res)) return;
      console.log("[StatusSeed] Starting seed...");
      const { SEED_CATEGORIES, SEED_STATUSES } = await import("./seed-statuses");
      console.log(`[StatusSeed] Loaded ${SEED_CATEGORIES.length} categories, ${SEED_STATUSES.length} statuses from config`);
      
      const existingCategories = await storage.getAllStatusCategories();
      const existingCatCodes = new Set(existingCategories.map((c: any) => c.code));
      const existingStatuses = await storage.getAllStatusDefinitions();
      const existingStatusCodes = new Set(existingStatuses.map((s: any) => s.code));

      const categoryMap: Record<string, string> = {};
      for (const ec of existingCategories) {
        categoryMap[ec.code] = ec.id;
      }
      let catCount = 0;
      for (const cat of SEED_CATEGORIES) {
        if (existingCatCodes.has(cat.code)) continue;
        const created = await storage.createStatusCategory({
          name: cat.name,
          code: cat.code,
          color: cat.color,
          icon: cat.icon,
          sortOrder: cat.sortOrder,
          isActive: true,
        });
        categoryMap[cat.code] = created.id;
        catCount++;
      }

      let statusCount = 0;
      const codeToId: Record<string, string> = {};
      const parentFixups: { id: string; parentCode: string }[] = [];

      for (const es of existingStatuses) {
        codeToId[es.code] = es.id;
      }
      for (const status of SEED_STATUSES) {
        if (existingStatusCodes.has(status.code)) continue;
        const categoryId = categoryMap[status.categoryCode];
        if (!categoryId) continue;
        const created = await storage.createStatusDefinition({
          categoryId,
          name: status.name,
          code: status.code,
          icon: status.icon,
          color: status.color,
          defaultAction: status.defaultAction,
          isFinal: status.isFinal,
          isConversion: status.isConversion,
          requiresNote: status.requiresNote,
          requiresCallback: status.requiresCallback,
          allowRecontact: status.allowRecontact,
          allowEmail: status.allowEmail,
          allowSms: status.allowSms,
          allowPhone: status.allowPhone,
          isSystemStatus: status.isSystemStatus,
          callbackOffsetDays: status.callbackOffsetDays,
          sortOrder: status.sortOrder,
          isActive: true,
          visibleInCampaigns: status.visibleInCampaigns,
        });
        codeToId[status.code] = created.id;
        if ((status as any).parentCode) {
          parentFixups.push({ id: created.id, parentCode: (status as any).parentCode });
        }
        statusCount++;
      }

      for (const fix of parentFixups) {
        const parentId = codeToId[fix.parentCode];
        if (parentId) {
          await storage.updateStatusDefinition(fix.id, { parentId });
        }
      }

      const msg = `Seeded ${catCount} new categories and ${statusCount} new statuses (${existingCategories.length} categories and ${existingStatuses.length} statuses already existed)`;
      console.log(`[StatusSeed] ${msg}`);
      res.json({ message: msg });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

